-- ----------------------------------------------------------------------------
-- Source: 20260117170000_jwt_role_sync.sql
-- ----------------------------------------------------------------------------

-- Migration: JWT Role Synchronization for Performance
-- Description: Sync profile roles to auth.users app_metadata for fast JWT role checks

-- Function to sync profile role to auth.users app_metadata
CREATE OR REPLACE FUNCTION public.sync_profile_role_to_auth()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, auth
AS $$
BEGIN
  UPDATE auth.users
  SET raw_app_meta_data = 
    CASE 
      WHEN raw_app_meta_data IS NULL THEN jsonb_build_object('role', NEW.role)
      ELSE raw_app_meta_data || jsonb_build_object('role', NEW.role)
    END
  WHERE id = NEW.id;

  RETURN NEW;
END;
$$;

-- Create trigger for automatic role sync
DROP TRIGGER IF EXISTS on_profile_role_sync ON public.profiles;
CREATE TRIGGER on_profile_role_sync
  AFTER INSERT OR UPDATE OF role ON public.profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_profile_role_to_auth();

-- Enhanced admin function with JWT optimization
CREATE OR REPLACE FUNCTION public.is_admin()
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Check JWT claim first (fastest, no recursion)
  IF (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin' THEN
    RETURN TRUE;
  END IF;

  -- Fallback to database check
  RETURN EXISTS (
    SELECT 1 FROM public.profiles 
    WHERE profiles.id = auth.uid() 
    AND profiles.role = 'admin'
  );
END;
$$;

-- Enhanced role checking function for future multi-role support
CREATE OR REPLACE FUNCTION public.has_role(required_role text)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Check JWT claim first (fastest)
  IF (auth.jwt() -> 'app_metadata' ->> 'role') = required_role THEN
    RETURN TRUE;
  END IF;

  -- Fallback to database check
  RETURN EXISTS (
    SELECT 1 FROM public.profiles 
    WHERE profiles.id = auth.uid() 
    AND profiles.role = required_role
  );
END;
$$;

-- Grant execute permissions to authenticated users
GRANT EXECUTE ON FUNCTION public.is_admin() TO authenticated;
GRANT EXECUTE ON FUNCTION public.has_role(text) TO authenticated;

-- Backfill existing roles to auth.users
DO $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN SELECT id, role FROM public.profiles LOOP
    UPDATE auth.users
    SET raw_app_meta_data = 
      CASE 
        WHEN raw_app_meta_data IS NULL THEN jsonb_build_object('role', r.role)
        ELSE raw_app_meta_data || jsonb_build_object('role', r.role)
      END
    WHERE id = r.id;
  END LOOP;
END;
$$;

-- Force schema cache reload
NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260117180000_analytics_search_rls.sql
-- ----------------------------------------------------------------------------

-- Search Analytics RLS Migration
-- Description: Enable admin access to global search analytics while maintaining user privacy
-- This allows console to provide real trending data to mobile app

-- 1. Create analytics function for global search insights
CREATE OR REPLACE FUNCTION get_search_analytics(
    days_back integer DEFAULT 7,
    limit_count integer DEFAULT 10
)
RETURNS TABLE(
    query text,
    search_count bigint,
    unique_users bigint,
    last_searched timestamptz,
    rank integer
)
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
    WITH search_analytics AS (
        SELECT 
            sh.query,
            COUNT(*) as search_count,
            COUNT(DISTINCT sh.user_id) as unique_users,
            MAX(sh.created_at) as last_searched,
            ROW_NUMBER() OVER (ORDER BY COUNT(*) DESC) as rank
        FROM public.search_history sh
        WHERE sh.created_at >= (now() - (days_back || ' days')::interval)
        GROUP BY sh.query
        ORDER BY search_count DESC
        LIMIT limit_count
    )
    SELECT 
        sa.query,
        sa.search_count,
        sa.unique_users,
        sa.last_searched,
        sa.rank
    FROM search_analytics sa;
$$;

-- 2. Create function for search analytics summary
CREATE OR REPLACE FUNCTION get_search_analytics_summary(
    days_back integer DEFAULT 30
)
RETURNS TABLE(
    total_searches bigint,
    unique_searchers bigint,
    unique_queries bigint,
    avg_searches_per_user numeric,
    top_query text
)
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
    SELECT 
        COUNT(*) as total_searches,
        COUNT(DISTINCT user_id) as unique_searchers,
        COUNT(DISTINCT query) as unique_queries,
        CASE 
            WHEN COUNT(DISTINCT user_id) > 0 
            THEN ROUND(COUNT(*)::numeric / COUNT(DISTINCT user_id), 2)
            ELSE 0 
        END as avg_searches_per_user,
        (SELECT query FROM (
            SELECT query, COUNT(*) as cnt
            FROM public.search_history
            WHERE created_at >= (now() - (days_back || ' days')::interval)
            GROUP BY query
            ORDER BY cnt DESC
            LIMIT 1
        ) top) as top_query
    FROM public.search_history
    WHERE created_at >= (now() - (days_back || ' days')::interval);
$$;

-- 3. Grant execute permissions to authenticated users (for admin access)
GRANT EXECUTE ON FUNCTION get_search_analytics(integer, integer) TO authenticated;
GRANT EXECUTE ON FUNCTION get_search_analytics_summary(integer) TO authenticated;

-- 4. Create admin-only policy for global search analytics
-- This allows admins to bypass RLS for analytics while maintaining user privacy

-- Drop existing public read policy if it exists
DROP POLICY IF EXISTS "Anyone can read trending searches" ON public.search_history;

-- Create admin analytics policy
CREATE POLICY "Admin analytics access to search_history"
ON public.search_history
FOR SELECT
TO authenticated
USING (
    -- Allow access if user is admin OR accessing their own data
    auth.uid() = user_id OR 
    EXISTS (
        SELECT 1 FROM public.profiles 
        WHERE id = auth.uid() 
        AND role = 'admin'
    )
);

-- 5. Create search_events table for better analytics tracking
CREATE TABLE IF NOT EXISTS public.search_events (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    query text,
    source text DEFAULT 'console',
    selected_key text,
    extra jsonb,
    created_at timestamptz DEFAULT now()
);

-- Enable RLS on search_events
ALTER TABLE public.search_events ENABLE ROW LEVEL SECURITY;

-- Policy for search_events - admins can read all, users can insert
CREATE POLICY "Admins can read all search events"
ON public.search_events
FOR SELECT
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.profiles 
        WHERE id = auth.uid() 
        AND role = 'admin'
    )
);

CREATE POLICY "Users can insert search events"
ON public.search_events
FOR INSERT
TO authenticated
WITH CHECK (true);

-- Grant permissions
GRANT SELECT ON public.search_events TO authenticated;
GRANT INSERT ON public.search_events TO authenticated;

-- 6. Create index for better performance
CREATE INDEX IF NOT EXISTS idx_search_events_created_at 
ON public.search_events(created_at DESC);

CREATE INDEX IF NOT EXISTS idx_search_events_query 
ON public.search_events(query);

-- Force schema cache reload
NOTIFY pgrst, 'reload schema';

-- 7. Create function to check if user is admin (helper for RLS)
CREATE OR REPLACE FUNCTION is_admin()
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
    SELECT EXISTS (
        SELECT 1 FROM public.profiles 
        WHERE id = auth.uid() 
        AND role = 'admin'
    );
$$;

-- Grant execute permission
GRANT EXECUTE ON FUNCTION is_admin() TO authenticated;


-- ----------------------------------------------------------------------------
-- Source: 20260117190000_auto_analytics_pipeline.sql
-- ----------------------------------------------------------------------------

-- Automatic Analytics Pipeline Migration
-- Creates automated system to populate trending_topics from search data
-- This enables global trending without touching app implementation

-- 1. Create function to automatically update trending_topics from search analytics
CREATE OR REPLACE FUNCTION update_trending_topics_from_search()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    analytics_period_days INTEGER := 7;
    max_topics INTEGER := 10;
    updated_rows INTEGER;
BEGIN
    -- Clear existing trending topics
    DELETE FROM public.trending_topics;
    
    -- Insert fresh trending data from search analytics
    INSERT INTO public.trending_topics (query, category, rank)
    SELECT 
        CASE 
            WHEN sa.search_count > 100 THEN sa.query || ' ðŸ”¥'
            ELSE sa.query
        END as query,
        CASE 
            WHEN sa.unique_users > 50 THEN 'Trending in Lagos'
            WHEN sa.search_count > 50 THEN 'Most Searched'
            ELSE 'Popular'
        END as category,
        sa.rank
    FROM get_search_analytics(analytics_period_days, max_topics) sa;
    
    -- Log the update
    GET DIAGNOSTICS updated_rows = ROW_COUNT;
    INSERT INTO public.search_events (query, source, selected_key, extra)
    VALUES ('trending_topics_update', 'system', 'auto_update', 
            jsonb_build_object('updated_rows', updated_rows, 'period_days', analytics_period_days));
    
END;
$$;

-- 2. Create scheduled job to update trending topics automatically
-- Note: This requires pg_cron extension. If not available, can be called manually.
-- SELECT cron.schedule('update-trending-topics', '0 */6 * * *', 'SELECT update_trending_topics_from_search();');

-- 3. Grant execute permissions
GRANT EXECUTE ON FUNCTION update_trending_topics_from_search() TO authenticated;

-- 4. Create trigger to automatically update trending topics when significant search activity occurs
CREATE OR REPLACE FUNCTION auto_update_trending_trigger()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
    -- Only update if this is a significant search activity
    -- Update trending topics every 50 new searches to avoid excessive updates
    IF (SELECT COUNT(*) FROM public.search_history WHERE created_at > NOW() - INTERVAL '1 hour') % 50 = 0 THEN
        PERFORM update_trending_topics_from_search();
    END IF;
    
    RETURN NEW;
END;
$$;

-- 5. Create trigger on search_history insertions
-- Note: This trigger may affect performance, consider using cron instead
-- CREATE TRIGGER trigger_auto_update_trending
-- AFTER INSERT ON public.search_history
-- FOR EACH STATEMENT
-- EXECUTE FUNCTION auto_update_trending_trigger();

-- 6. Create admin function to manually trigger trending updates
CREATE OR REPLACE FUNCTION admin_update_trending_topics(
    days_back integer DEFAULT 7,
    limit_count integer DEFAULT 10
)
RETURNS TABLE(
    query text,
    category text,
    rank integer,
    search_count bigint,
    unique_users bigint
)
LANGUAGE sql
SECURITY DEFINER
AS $$
    -- First update the trending_topics table
    SELECT update_trending_topics_from_search();
    
    -- Then return the updated data with analytics
    SELECT 
        tt.query,
        tt.category,
        tt.rank,
        sa.search_count,
        sa.unique_users
    FROM public.trending_topics tt
    LEFT JOIN get_search_analytics(days_back, limit_count) sa ON tt.query = sa.query
    ORDER BY tt.rank;
$$;

-- Grant execute permissions for admin function
GRANT EXECUTE ON FUNCTION admin_update_trending_topics(integer, integer) TO authenticated;

-- 7. Create view for real-time trending analytics (read-only for mobile app)
CREATE OR REPLACE VIEW public.trending_searches_view AS
SELECT 
    tt.query,
    tt.rank,
    tt.category,
    COALESCE(sa.search_count, 100 - (tt.rank * 10)) as search_count,
    COALESCE(sa.unique_users, 20 - (tt.rank * 2)) as unique_users,
    tt.updated_at
FROM public.trending_topics tt
LEFT JOIN LATERAL (
    SELECT search_count, unique_users 
    FROM get_search_analytics(7, 20) 
    WHERE query = tt.query
    LIMIT 1
) sa ON true
ORDER BY tt.rank;

-- Grant read access to the view for everyone
GRANT SELECT ON public.trending_searches_view TO authenticated;
GRANT SELECT ON public.trending_searches_view TO anon;

-- 8. Update the original get_trending_searches function to use the new system
CREATE OR REPLACE FUNCTION get_trending_searches(
    days_back integer DEFAULT 7,
    limit_count integer DEFAULT 8
)
RETURNS TABLE(query text, count bigint)
LANGUAGE sql
STABLE
AS $$
    -- Use the view which combines static trending topics with real analytics
    SELECT 
        query,
        search_count as count
    FROM public.trending_searches_view
    ORDER BY rank
    LIMIT limit_count;
$$;

-- Force schema cache reload
NOTIFY pgrst, 'reload schema';

-- 9. Initial population of trending topics
SELECT update_trending_topics_from_search();


