-- ----------------------------------------------------------------------------
-- Source: 20260215000100_insurance_enrollment_logic.sql
-- ----------------------------------------------------------------------------

-- Migration: Insurance Enrollment Logic
-- Description: Sets up the functions and triggers for iVisit Basic.

-- Function
CREATE OR REPLACE FUNCTION public.enroll_basic_insurance(p_user_id UUID)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public
AS $$
DECLARE
    v_policy_number TEXT;
BEGIN
    IF EXISTS (SELECT 1 FROM public.insurance_policies WHERE user_id = p_user_id) THEN
        RETURN;
    END IF;

    v_policy_number := 'IV-BASIC-' || UPPER(SUBSTR(MD5(RANDOM()::TEXT), 1, 8));

    EXECUTE 'INSERT INTO public.insurance_policies (
        user_id, provider_name, policy_number, plan_type, status, 
        is_default, coverage_details, starts_at, expires_at
    ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)'
    USING p_user_id, 'iVisit Basic', v_policy_number, 'basic', 'active', 
          TRUE, 
          '{"trip_limit": 1, "amount_limit": 50000, "description": "Covers 1 emergency ambulance trip per year", "type": "emergency_transport"}'::jsonb,
          NOW(), (NOW() + INTERVAL '1 year');
END;
$$;

-- Trigger
CREATE OR REPLACE FUNCTION public.handle_new_user_insurance()
RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path = public
AS $$ BEGIN PERFORM public.enroll_basic_insurance(NEW.id); RETURN NEW; END; $$;

DROP TRIGGER IF EXISTS on_profile_created_enroll_insurance ON public.profiles;
CREATE TRIGGER on_profile_created_enroll_insurance
    AFTER INSERT ON public.profiles FOR EACH ROW EXECUTE FUNCTION public.handle_new_user_insurance();

-- Backfill (One-off)
DO $$
DECLARE
    r RECORD;
BEGIN
    FOR r IN SELECT id FROM public.profiles p WHERE NOT EXISTS (SELECT 1 FROM public.insurance_policies ip WHERE ip.user_id = p.id) LOOP
        BEGIN
            PERFORM public.enroll_basic_insurance(r.id);
        EXCEPTION WHEN OTHERS THEN
            RAISE NOTICE 'Failed to enroll user %: %', r.id, SQLERRM;
        END;
    END LOOP;
END $$;


-- ----------------------------------------------------------------------------
-- Source: 20260215000500_fix_nearby_hospitals_types.sql
-- ----------------------------------------------------------------------------

-- Migration: Fix Type Mismatch in nearby_hospitals RPC
-- Description: Casts google_rating (numeric/decimal) and distance calculations to double precision to match the function signature.

CREATE OR REPLACE FUNCTION nearby_hospitals(
    user_lat double precision,
    user_lng double precision,
    radius_km integer DEFAULT 50
)
RETURNS TABLE (
    id uuid,
    name text,
    address text,
    phone text,
    rating double precision,
    type text,
    image text,
    specialties text[],
    service_types text[],
    features text[],
    emergency_level text,
    available_beds integer,
    ambulances_count integer,
    wait_time text,
    price_range text,
    latitude double precision,
    longitude double precision,
    verified boolean,
    status text,
    distance_km double precision,
    -- New Google Places fields
    place_id text,
    google_address text,
    google_phone text,
    google_rating double precision, -- Signature expects double precision
    google_photos text[],
    google_opening_hours jsonb,
    google_types text[],
    google_website text,
    import_status text,
    org_admin_id uuid,
    created_at timestamp with time zone,
    updated_at timestamp with time zone
)
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY
    SELECT 
        h.id,
        h.name,
        h.address,
        h.phone,
        h.rating,
        h.type,
        h.image,
        h.specialties,
        h.service_types,
        h.features,
        h.emergency_level,
        h.available_beds,
        h.ambulances_count,
        h.wait_time,
        h.price_range,
        h.latitude,
        h.longitude,
        h.verified,
        h.status,
        -- Calculate distance using PostGIS and ensure it is double precision
        CASE 
            WHEN h.latitude IS NOT NULL AND h.longitude IS NOT NULL THEN
                (ST_Distance(
                    ST_MakePoint(user_lng, user_lat)::geography,
                    ST_MakePoint(h.longitude, h.latitude)::geography
                ) / 1000.0)::double precision
            ELSE NULL
        END as distance_km,
        -- New Google Places fields
        h.place_id,
        h.google_address,
        h.google_phone,
        h.google_rating::double precision, -- Explicitly cast numeric(3,2) to double precision
        h.google_photos,
        h.google_opening_hours,
        h.google_types,
        h.google_website,
        h.import_status,
        h.org_admin_id,
        h.created_at,
        h.updated_at
    FROM public.hospitals h
    WHERE 
        -- Only include verified hospitals with available status
        h.verified = true 
        AND h.status = 'available'
        AND h.latitude IS NOT NULL 
        AND h.longitude IS NOT NULL
        -- Filter by radius
        AND ST_DWithin(
            ST_MakePoint(user_lng, user_lat)::geography,
            ST_MakePoint(h.longitude, h.latitude)::geography,
            radius_km * 1000 -- Convert km to meters
        )
    ORDER BY distance_km ASC;
END;
$$;


-- ----------------------------------------------------------------------------
-- Source: 20260215001000_backfill_display_ids.sql
-- ----------------------------------------------------------------------------

-- Migration: Backfill Display IDs for existing users and hospitals
-- Description: Ensures all existing records in profiles and hospitals have an entry in id_mappings.

DO $$
DECLARE
    profile_rec RECORD;
    hospital_rec RECORD;
BEGIN
    -- 1. Backfill Profiles
    FOR profile_rec IN (
        SELECT id, role FROM public.profiles 
        WHERE id NOT IN (SELECT entity_id FROM public.id_mappings)
    ) LOOP
        -- Reuse the existing trigger function logic to generate IDs
        -- It uses generate_display_id(prefix)
        PERFORM public.on_profile_created_generate_id_logic(profile_rec.id, profile_rec.role);
    END LOOP;

    -- 2. Backfill Hospitals
    FOR hospital_rec IN (
        SELECT id FROM public.hospitals 
        WHERE id NOT IN (SELECT entity_id FROM public.id_mappings)
    ) LOOP
        INSERT INTO public.id_mappings (entity_type, entity_id, display_id)
        VALUES ('hospital', hospital_rec.id, public.generate_display_id('ORG'))
        ON CONFLICT DO NOTHING;
    END LOOP;
END $$;

-- Helper to allow manual trigger logic execution for backfills
CREATE OR REPLACE FUNCTION public.on_profile_created_generate_id_logic(p_id UUID, p_role TEXT)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    prefix TEXT;
    entity_type_val TEXT;
    display_id TEXT;
BEGIN
    IF p_role = 'patient' THEN
        prefix := 'IVP';
        entity_type_val := 'patient';
    ELSIF p_role IN ('admin', 'org_admin') THEN
        prefix := 'ADM';
        entity_type_val := 'admin';
    ELSIF p_role = 'dispatcher' THEN
        prefix := 'DSP';
        entity_type_val := 'dispatcher';
    ELSIF p_role = 'provider' THEN
        prefix := 'PRV';
        entity_type_val := 'provider';
    ELSE
        -- No prefix for other roles
        RETURN;
    END IF;
    
    display_id := public.generate_display_id(prefix);
    
    INSERT INTO public.id_mappings (entity_type, entity_id, display_id)
    VALUES (entity_type_val, p_id, display_id)
    ON CONFLICT (entity_type, entity_id) DO NOTHING;
END;
$$;

-- Run backfill again using the helper just in case
SELECT public.on_profile_created_generate_id_logic(p.id, p.role)
FROM public.profiles p
WHERE p.id NOT IN (SELECT entity_id FROM public.id_mappings);

NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260215150000_wallet_operations_rpc.sql
-- ----------------------------------------------------------------------------

-- Migration: Financial Projections & Analytics Extensions
-- Provides read-only analytics for the Wallet Intelligence engine

-- 1. Function to calculate 30d projected revenue
-- This follows the "Reflection" model: it looks at confirmed ledger credits
CREATE OR REPLACE FUNCTION public.get_wallet_projection(
    p_organization_id UUID DEFAULT NULL
)
RETURNS DECIMAL AS $$
DECLARE
    v_total_30d DECIMAL;
BEGIN
    SELECT COALESCE(SUM(amount), 0) INTO v_total_30d
    FROM public.wallet_ledger
    WHERE (transaction_type = 'credit' OR transaction_type = 'payment')
    AND created_at >= NOW() - INTERVAL '30 days'
    AND (p_organization_id IS NULL OR organization_id = p_organization_id);

    -- Simple reflection: last 30 days revenue used as next 30 days projection
    RETURN v_total_30d;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Permissions
GRANT EXECUTE ON FUNCTION public.get_wallet_projection(UUID) TO authenticated;

-- Notify PostgREST to reload schema
NOTIFY pgrst, 'reload schema';


