        'payout_method_last4', payout_method_last4,
        'payout_method_brand', payout_method_brand,
        'is_active', is_active
    ) INTO v_details
    FROM public.organizations
    WHERE id = p_org_id;
    
    RETURN v_details;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

