-- ============================================================
-- Migration: FIX INSURANCE ENROLLMENT + BACKFILL PROFILES
-- ============================================================
-- 1. Fix enroll_basic_insurance() â€” remove "status" column ref
-- 2. Backfill profiles from auth.users
-- 3. Cascade to preferences, medical_profiles, patient_wallets  
--    (triggers handle insurance auto-enrollment)
-- ============================================================

BEGIN;

-- ============================================================
-- 1. FIX: enroll_basic_insurance â€” drop "status" from INSERT
-- ============================================================
CREATE OR REPLACE FUNCTION public.enroll_basic_insurance(p_user_id UUID)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public
AS $$
DECLARE
    v_policy_number TEXT;
BEGIN
    IF EXISTS (SELECT 1 FROM public.insurance_policies WHERE user_id::text = p_user_id::text) THEN
        RETURN;
    END IF;

    v_policy_number := 'IV-BASIC-' || UPPER(SUBSTR(MD5(RANDOM()::TEXT), 1, 8));

    INSERT INTO public.insurance_policies (
        user_id, provider_name, policy_number, plan_type,
        is_default, coverage_details, starts_at, expires_at
    ) VALUES (
        p_user_id, 'iVisit Basic', v_policy_number, 'basic',
        TRUE,
        '{"trip_limit": 1, "amount_limit": 50000, "description": "Covers 1 emergency ambulance trip per year", "type": "emergency_transport"}'::jsonb,
        NOW(), (NOW() + INTERVAL '1 year')
    );
END;
$$;

-- ============================================================
-- 2. BACKFILL: profiles from auth.users
-- ============================================================
INSERT INTO public.profiles (id, email, phone, full_name, avatar_url, image_uri, created_at, updated_at)
SELECT
  u.id,
  u.email,
  u.phone,
  u.raw_user_meta_data->>'full_name',
  u.raw_user_meta_data->>'avatar_url',
  u.raw_user_meta_data->>'avatar_url',
  COALESCE(u.created_at, now()),
  now()
FROM auth.users u
WHERE NOT EXISTS (
  SELECT 1 FROM public.profiles p WHERE p.id::text = u.id::text
);
-- NOTE: profile INSERT triggers auto-create:
--   â†’ preferences (handle_new_user triggers on auth.users, but we also backfill below)
--   â†’ medical_profiles (on_profile_created_medical trigger)
--   â†’ patient_wallets (on_profile_created_create_wallet trigger)
--   â†’ insurance_policies (on_profile_created_enroll_insurance trigger)
--   â†’ username auto-generation (on_profile_set_username trigger)

-- ============================================================
-- 3. BACKFILL: preferences (in case trigger didn't fire)
-- ============================================================
INSERT INTO public.preferences (user_id)
SELECT p.id
FROM public.profiles p
WHERE NOT EXISTS (
  SELECT 1 FROM public.preferences pr WHERE pr.user_id::text = p.id::text
);

-- ============================================================
-- 4. BACKFILL: medical_profiles
-- ============================================================
INSERT INTO public.medical_profiles (user_id)
SELECT p.id
FROM public.profiles p
WHERE NOT EXISTS (
  SELECT 1 FROM public.medical_profiles mp WHERE mp.user_id::text = p.id::text
);

-- ============================================================
-- 5. BACKFILL: patient_wallets
-- ============================================================
INSERT INTO public.patient_wallets (user_id)
SELECT p.id
FROM public.profiles p
WHERE NOT EXISTS (
  SELECT 1 FROM public.patient_wallets pw WHERE pw.user_id::text = p.id::text
);

NOTIFY pgrst, 'reload schema';

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260216004000_sync_profile_metadata.sql
-- ----------------------------------------------------------------------------

-- ============================================================
-- Migration: SYNC PROFILE ROLES AND METADATA (FIXED)
-- ============================================================
-- 1. Updates handle_new_user() to sync human roles and names.
-- 2. Performs a one-time SYNC of all existing profiles.
-- 3. FIX: Removed provider_type sync (auth provider != medical provider).
-- ============================================================

BEGIN;

-- 1. Updated Function (Fixed)
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_full_name TEXT;
  v_first_name TEXT;
  v_last_name TEXT;
  v_role TEXT;
BEGIN
  v_full_name := NEW.raw_user_meta_data->>'full_name';
  v_role := COALESCE(NEW.raw_app_meta_data->>'role', 'patient');

  -- Ensure role is valid for the constraint
  IF v_role NOT IN ('patient', 'provider', 'admin') THEN
    v_role := 'patient';
  END IF;
  
  -- Name splitting
  IF v_full_name IS NOT NULL THEN
    v_first_name := split_part(v_full_name, ' ', 1);
    v_last_name := CASE 
      WHEN position(' ' in v_full_name) > 0 
      THEN substring(v_full_name from position(' ' in v_full_name) + 1)
      ELSE NULL 
    END;
  END IF;

  INSERT INTO public.profiles (
    id, 
    email, 
    phone, 
    full_name, 
    first_name, 
    last_name,
    avatar_url, 
    image_uri, 
    role, 
    created_at, 
    updated_at
  )
  VALUES (
    NEW.id,
    NEW.email,
    NEW.phone,
    v_full_name,
    v_first_name,
    v_last_name,
    NEW.raw_user_meta_data->>'avatar_url',
    NEW.raw_user_meta_data->>'avatar_url',
    v_role,
    now(),
    now()
  )
  ON CONFLICT (id) DO UPDATE SET
    email = EXCLUDED.email,
    phone = EXCLUDED.phone,
    full_name = COALESCE(profiles.full_name, EXCLUDED.full_name),
    first_name = COALESCE(profiles.first_name, EXCLUDED.first_name),
    last_name = COALESCE(profiles.last_name, EXCLUDED.last_name),
    role = COALESCE(profiles.role, EXCLUDED.role),
    updated_at = now();

  INSERT INTO public.preferences (user_id)
  VALUES (NEW.id)
  ON CONFLICT (user_id) DO NOTHING;

  RETURN NEW;
END;
$$;

-- 2. Run Sync for existing users
DO $$
DECLARE
  u RECORD;
  v_full_name TEXT;
  v_first_name TEXT;
  v_last_name TEXT;
  v_role TEXT;
BEGIN
  FOR u IN SELECT * FROM auth.users LOOP
    v_full_name := u.raw_user_meta_data->>'full_name';
    v_role := u.raw_app_meta_data->>'role';

    -- Validate role before update
    IF v_role NOT IN ('patient', 'provider', 'admin') THEN
      v_role := NULL;
    END IF;
    
    IF v_full_name IS NOT NULL THEN
      v_first_name := split_part(v_full_name, ' ', 1);
      v_last_name := CASE 
        WHEN position(' ' in v_full_name) > 0 
        THEN substring(v_full_name from position(' ' in v_full_name) + 1)
        ELSE NULL 
      END;
    END IF;

    UPDATE public.profiles
    SET 
      role = COALESCE(v_role, role, 'patient'),
      full_name = COALESCE(full_name, v_full_name),
      first_name = COALESCE(first_name, v_first_name),
      last_name = COALESCE(last_name, v_last_name),
      updated_at = now()
    WHERE id::text = u.id::text;
  END LOOP;
END $$;

NOTIFY pgrst, 'reload schema';

COMMIT;


