-- ----------------------------------------------------------------------------
-- Source: 20260216070500_fix_delete_user_profiles.sql
-- ----------------------------------------------------------------------------

-- Migration: Fix delete_user_by_admin to handle profile-only users
--
-- BUG: The function only deleted from auth.users. Users that exist only
-- in profiles (no auth.users entry) were silently "deleted" (0 rows affected)
-- but their profile remained. After reload, user was still there.
--
-- FIX: Delete from profiles first, then auth.users. Both are guarded
-- so missing rows don't cause errors.

DROP FUNCTION IF EXISTS public.delete_user_by_admin(uuid);

CREATE OR REPLACE FUNCTION public.delete_user_by_admin(target_user_id uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- 1. Check if the executing user is an Admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid() AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Access Denied: Only Admins can delete users.';
  END IF;

  -- 2. Verify target user exists (in either table)
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles WHERE id = target_user_id
  ) AND NOT EXISTS (
    SELECT 1 FROM auth.users WHERE id = target_user_id
  ) THEN
    RAISE EXCEPTION 'User not found: %', target_user_id;
  END IF;

  -- 3. Delete profile first (no FK cascade assumed)
  DELETE FROM public.profiles WHERE id = target_user_id;

  -- 4. Delete auth entry if it exists
  DELETE FROM auth.users WHERE id = target_user_id;
END;
$$;

GRANT EXECUTE ON FUNCTION public.delete_user_by_admin(target_user_id uuid) TO authenticated;

COMMENT ON FUNCTION public.delete_user_by_admin(uuid) IS
'Deletes a user from both profiles and auth.users. Handles profile-only users (no auth entry) and auth-only users. Only admins can execute.';

NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260216070600_fix_notifications_rls.sql
-- ----------------------------------------------------------------------------

-- Migration: Fix notifications RLS and FK for admin operations
--
-- ISSUES:
-- 1. INSERT policy: `auth.uid() = user_id` blocks admins from creating
--    notifications for other users or system notifications
-- 2. FK constraint: `user_id references auth.users(id)` fails when creating
--    notifications for profile-only users (no auth entry)
--
-- FIX:
-- 1. Add admin INSERT policy (admins can create notifications for anyone)
-- 2. Drop FK to auth.users, add FK to profiles instead (profiles is source of truth)
-- 3. Add a "system can insert" policy for authenticated users creating
--    notifications where user_id = their own ID (keep existing behavior)

-- Step 1: Drop the old FK constraint on user_id -> auth.users
-- First find and drop it
DO $$
DECLARE
    fk_name text;
BEGIN
    SELECT conname INTO fk_name
    FROM pg_constraint
    WHERE conrelid = 'public.notifications'::regclass
    AND confrelid = 'auth.users'::regclass;
    
    IF fk_name IS NOT NULL THEN
        EXECUTE format('ALTER TABLE public.notifications DROP CONSTRAINT %I', fk_name);
    END IF;
END $$;

-- Step 2: Add FK to profiles instead (profiles is the source of truth)
-- Use ON DELETE CASCADE so deleting a profile cleans up their notifications
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conrelid = 'public.notifications'::regclass
        AND confrelid = 'public.profiles'::regclass
    ) THEN
        ALTER TABLE public.notifications
        ADD CONSTRAINT notifications_user_id_fkey
        FOREIGN KEY (user_id) REFERENCES public.profiles(id) ON DELETE CASCADE;
    END IF;
END $$;

-- Step 3: Fix RLS policies
-- Keep existing self-insert policy
-- Add admin insert policy (admins can create notifications for any user)

DROP POLICY IF EXISTS "Admins can insert notifications" ON public.notifications;
CREATE POLICY "Admins can insert notifications"
ON public.notifications
FOR INSERT
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE id = auth.uid() AND role = 'admin'
    )
);

-- Also allow admins to view all notifications (for admin dashboard)
DROP POLICY IF EXISTS "Admins can view all notifications" ON public.notifications;
CREATE POLICY "Admins can view all notifications"
ON public.notifications
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE id = auth.uid() AND role = 'admin'
    )
);

-- Also allow admins to update any notification
DROP POLICY IF EXISTS "Admins can update all notifications" ON public.notifications;
CREATE POLICY "Admins can update all notifications"
ON public.notifications
FOR UPDATE
USING (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE id = auth.uid() AND role = 'admin'
    )
);

-- Also allow admins to delete any notification
DROP POLICY IF EXISTS "Admins can delete all notifications" ON public.notifications;
CREATE POLICY "Admins can delete all notifications"
ON public.notifications
FOR DELETE
USING (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE id = auth.uid() AND role = 'admin'
    )
);

NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260216070700_add_delete_hospital_rpc.sql
-- ----------------------------------------------------------------------------

-- Migration: Add delete_hospital_by_admin RPC
--
-- The direct supabase.from('hospitals').delete() goes through RLS,
-- but the FOR ALL policy using get_current_user_role() = 'admin'
-- silently returns 0 rows (DELETE succeeds with nothing deleted).
-- This SECURITY DEFINER RPC bypasses RLS for reliable admin deletes.

CREATE OR REPLACE FUNCTION public.delete_hospital_by_admin(target_hospital_id uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- 1. Verify caller is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid() AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Access Denied: Only Admins can delete hospitals.';
  END IF;

  -- 2. Verify hospital exists
  IF NOT EXISTS (
    SELECT 1 FROM public.hospitals WHERE id = target_hospital_id
  ) THEN
    RAISE EXCEPTION 'Hospital not found: %', target_hospital_id;
  END IF;

  -- 3. Delete related ambulances first (FK constraint)
  DELETE FROM public.ambulances WHERE hospital_id = target_hospital_id;

  -- 4. Delete the hospital
  DELETE FROM public.hospitals WHERE id = target_hospital_id;
END;
$$;

GRANT EXECUTE ON FUNCTION public.delete_hospital_by_admin(uuid) TO authenticated;

COMMENT ON FUNCTION public.delete_hospital_by_admin(uuid) IS
'Deletes a hospital and its ambulances. SECURITY DEFINER bypasses RLS. Only admins can execute.';

NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260216070800_add_update_profile_rpc.sql
-- ----------------------------------------------------------------------------

-- Migration: Add update_profile_by_admin RPC
--
-- ROOT CAUSE (same as delete): The FOR UPDATE RLS policy
--   "Admins can update any profile" USING (get_current_user_role() = 'admin')
-- silently excludes the target row from the UPDATE scope.
-- The PATCH returns 200 with 0 rows, and .single() throws PGRST116.
--
-- FIX: SECURITY DEFINER RPC bypasses RLS and checks admin role explicitly.

CREATE OR REPLACE FUNCTION public.update_profile_by_admin(
  target_user_id uuid,
  profile_data jsonb
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result jsonb;
  allowed_keys text[] := ARRAY[
    'email', 'phone', 'username', 'first_name', 'last_name', 'full_name',
    'image_uri', 'role', 'organization_id', 'provider_type',
    'bvn_verified', 'address', 'gender', 'date_of_birth', 'updated_at'
  ];
  filtered_data jsonb := '{}';
  k text;
BEGIN
  -- 1. Verify caller is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid() AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Access Denied: Only Admins can update other users profiles.';
  END IF;

  -- 2. Verify target profile exists
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles WHERE id = target_user_id
  ) THEN
    RAISE EXCEPTION 'Profile not found: %', target_user_id;
  END IF;

  -- 3. Whitelist fields (prevent injecting arbitrary columns)
  FOR k IN SELECT jsonb_object_keys(profile_data)
  LOOP
    IF k = ANY(allowed_keys) THEN
      filtered_data := filtered_data || jsonb_build_object(k, profile_data->k);
    END IF;
  END LOOP;

  -- 4. Always set updated_at
  filtered_data := filtered_data || jsonb_build_object('updated_at', now());

  -- 5. Perform the update using dynamic SQL with whitelisted fields
  UPDATE public.profiles
  SET
    email = COALESCE((filtered_data->>'email'), email),
    phone = COALESCE((filtered_data->>'phone'), phone),
    username = COALESCE((filtered_data->>'username'), username),
    first_name = COALESCE((filtered_data->>'first_name'), first_name),
    last_name = COALESCE((filtered_data->>'last_name'), last_name),
    full_name = COALESCE((filtered_data->>'full_name'), full_name),
    image_uri = COALESCE((filtered_data->>'image_uri'), image_uri),
    role = COALESCE((filtered_data->>'role'), role),
    organization_id = CASE
      WHEN filtered_data ? 'organization_id' THEN
        NULLIF(filtered_data->>'organization_id', '')::uuid
      ELSE organization_id
    END,
    provider_type = COALESCE((filtered_data->>'provider_type'), provider_type),
    bvn_verified = CASE
      WHEN filtered_data ? 'bvn_verified' THEN (filtered_data->>'bvn_verified')::boolean
      ELSE bvn_verified
    END,
    address = COALESCE((filtered_data->>'address'), address),
    gender = COALESCE((filtered_data->>'gender'), gender),
    date_of_birth = COALESCE((filtered_data->>'date_of_birth'), date_of_birth),
    updated_at = now()
  WHERE id = target_user_id;

  -- 6. Return the updated profile
  SELECT to_jsonb(p) INTO result
  FROM public.profiles p
  WHERE p.id = target_user_id;

  RETURN result;
END;
$$;

