    IF caller_org_id IS NULL OR hospital_org_id IS NULL OR caller_org_id != hospital_org_id THEN
      RAISE EXCEPTION 'Org admin cannot update hospitals outside their organization';
    END IF;
  ELSE
    RAISE EXCEPTION 'Only admins and org_admins can update hospitals';
  END IF;

  -- Strip fields that don't exist in the table
  payload = payload - 'total_beds' - 'reserved_beds' - 'display_id'
                     - 'google_photos' - 'id' - 'created_at';

  -- Perform the update
  UPDATE public.hospitals
  SET
    name              = COALESCE((payload->>'name')::TEXT, name),
    address           = COALESCE((payload->>'address')::TEXT, address),
    phone             = (payload->>'phone')::TEXT,
    rating            = COALESCE((payload->>'rating')::NUMERIC, rating),
    type              = COALESCE((payload->>'type')::TEXT, type),
    image             = (payload->>'image')::TEXT,
    specialties       = CASE WHEN payload ? 'specialties' AND jsonb_typeof(payload->'specialties') = 'array' 
                             THEN ARRAY(SELECT jsonb_array_elements_text(payload->'specialties'))::TEXT[] 
                             ELSE specialties END,
    service_types     = CASE WHEN payload ? 'service_types' AND jsonb_typeof(payload->'service_types') = 'array' 
                             THEN ARRAY(SELECT jsonb_array_elements_text(payload->'service_types'))::TEXT[] 
                             ELSE service_types END,
    features          = CASE WHEN payload ? 'features' AND jsonb_typeof(payload->'features') = 'array' 
                             THEN ARRAY(SELECT jsonb_array_elements_text(payload->'features'))::TEXT[] 
                             ELSE features END,
    emergency_services = CASE WHEN payload ? 'emergency_services' AND jsonb_typeof(payload->'emergency_services') = 'array' 
                             THEN ARRAY(SELECT jsonb_array_elements_text(payload->'emergency_services'))::TEXT[] 
                             ELSE emergency_services END,
    emergency_level   = (payload->>'emergency_level')::TEXT,
    available_beds    = COALESCE((payload->>'available_beds')::INT, available_beds),
    ambulances_count  = COALESCE((payload->>'ambulances_count')::INT, ambulances_count),
    wait_time         = (payload->>'wait_time')::TEXT,
    price_range       = (payload->>'price_range')::TEXT,
    latitude          = CASE WHEN payload ? 'latitude' THEN (payload->>'latitude')::NUMERIC ELSE latitude END,
    longitude         = CASE WHEN payload ? 'longitude' THEN (payload->>'longitude')::NUMERIC ELSE longitude END,
    verified          = COALESCE((payload->>'verified')::BOOLEAN, verified),
    verification_status = COALESCE((payload->>'verification_status')::TEXT, verification_status),
    status            = COALESCE((payload->>'status')::TEXT, status),
    organization_id   = CASE
                          WHEN payload ? 'organization_id' AND payload->>'organization_id' != ''
                          THEN (payload->>'organization_id')::UUID
                          ELSE organization_id
                        END,
    updated_at        = now()
  WHERE id = target_hospital_id::UUID;

  -- Return the updated row
  SELECT to_jsonb(h.*) INTO result
  FROM public.hospitals h
  WHERE h.id = target_hospital_id::UUID;

  RETURN result;
END;
$$;


-- ----------------------------------------------------------------------------
-- Source: 20260216091000_add_org_name_to_users_rpc.sql
-- ----------------------------------------------------------------------------

-- Migration: Add Organization Name to get_all_auth_users RPC
-- Description: Updates get_all_auth_users to join with hospitals table to return the organization name.

-- Drop existing function
DROP FUNCTION IF EXISTS public.get_all_auth_users(uuid);

-- Recreate with organization name join
CREATE OR REPLACE FUNCTION public.get_all_auth_users(p_organization_id uuid DEFAULT NULL)
RETURNS TABLE (
  id uuid,
  email text,
  phone text,
  created_at timestamptz,
  updated_at timestamptz,
  last_sign_in_at timestamptz,
  email_confirmed_at timestamptz,
  phone_confirmed_at timestamptz,
  banned_until timestamptz,
  profile_role text,
  profile_username text,
  profile_first_name text,
  profile_last_name text,
  profile_full_name text,
  profile_provider_type text,
  profile_bvn_verified boolean,
  profile_display_id text,
  organization_id uuid,
  organization_name text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    caller_role text;
    caller_org_id uuid;
    effective_org_filter uuid;
BEGIN
    -- Get caller's role and organization
    SELECT p.role, p.organization_id 
    INTO caller_role, caller_org_id
    FROM public.profiles p
    WHERE p.id = auth.uid();

    -- Check if caller has admin privileges
    IF caller_role NOT IN ('admin', 'org_admin', 'dispatcher') THEN
        RAISE EXCEPTION 'Access denied: Invalid role for user management';
    END IF;

    -- Determine effective organization filter based on role
    IF caller_role = 'admin' THEN
        -- Super admin: use the provided filter (null = all users)
        effective_org_filter := p_organization_id;
    ELSIF caller_role IN ('org_admin', 'dispatcher') THEN
        -- Org-scoped roles: always filter by their own organization
        effective_org_filter := caller_org_id;
    ELSE
        effective_org_filter := caller_org_id;
    END IF;

    -- Return ALL profiles, enriched with auth data and organization name
    RETURN QUERY
    SELECT 
        p3.id,
        COALESCE(au.email::text, p3.email::text) as email,
        COALESCE(au.phone::text, p3.phone::text) as phone,
        COALESCE(au.created_at, p3.created_at) as created_at,
        COALESCE(au.updated_at, p3.updated_at) as updated_at,
        au.last_sign_in_at,
        au.email_confirmed_at,
        au.phone_confirmed_at,
        au.banned_until,
        p3.role::text as profile_role,
        p3.username as profile_username,
        p3.first_name as profile_first_name,
        p3.last_name as profile_last_name,
        p3.full_name as profile_full_name,
        p3.provider_type as profile_provider_type,
        p3.bvn_verified as profile_bvn_verified,
        p3.display_id as profile_display_id,
        p3.organization_id,
        h.name as organization_name
    FROM public.profiles p3
    LEFT JOIN auth.users au ON au.id = p3.id
    LEFT JOIN public.hospitals h ON h.organization_id = p3.organization_id
    WHERE (effective_org_filter IS NULL OR p3.organization_id = effective_org_filter)
    ORDER BY p3.created_at DESC;
END;
$$;

-- Grant permissions
GRANT EXECUTE ON FUNCTION public.get_all_auth_users(uuid) TO authenticated;

