-- ----------------------------------------------------------------------------
-- Source: 20260216210000_fix_room_pricing_and_users.sql
-- ----------------------------------------------------------------------------

-- Migration: Fix Room Pricing RLS and User Visibility
-- Description: 
-- 1. Adds permissive RLS to room_pricing so data is visible.
-- 2. Updates get_all_auth_users to use FULL OUTER JOIN to catch 'orphaned' profiles.
-- 3. Ensures hospital_id column compatibility.

BEGIN;

--------------------------------------------------------------------------------
-- 1. Fix Room Pricing RLS
--------------------------------------------------------------------------------
ALTER TABLE public.room_pricing ENABLE ROW LEVEL SECURITY;

-- Drop existing restrictive policies to be safe
DROP POLICY IF EXISTS "Public view active room pricing" ON public.room_pricing;
DROP POLICY IF EXISTS "Enable read access for all users" ON public.room_pricing;

-- Create a permissive policy for reading (Authenticated + Anon if needed, but usually Authenticated)
CREATE POLICY "Enable read access for all users"
ON public.room_pricing
FOR SELECT
USING (true);


--------------------------------------------------------------------------------
-- 2. Fix User Visibility (FULL OUTER JOIN)
--------------------------------------------------------------------------------
DROP FUNCTION IF EXISTS public.get_all_auth_users(UUID);

CREATE OR REPLACE FUNCTION public.get_all_auth_users(p_organization_id UUID DEFAULT NULL)
RETURNS TABLE (
    id UUID,
    email TEXT,
    phone TEXT,
    username TEXT,
    role TEXT,
    first_name TEXT,
    last_name TEXT,
    full_name TEXT,
    image_uri TEXT,
    avatar_url TEXT,
    organization_id UUID,
    organization_name TEXT,
    provider_type TEXT,
    bvn_verified BOOLEAN,
    display_id TEXT,
    created_at TIMESTAMPTZ,
    last_sign_in_at TIMESTAMPTZ,
    profile_role TEXT,
    profile_username TEXT,
    profile_first_name TEXT,
    profile_last_name TEXT,
    profile_full_name TEXT,
    profile_image_uri TEXT,
    profile_avatar_url TEXT,
    profile_organization_id UUID,
    profile_organization_name TEXT,
    profile_provider_type TEXT,
    profile_bvn_verified BOOLEAN,
    profile_display_id TEXT
) 
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(au.id, p.id) as id, -- Handle orphan profiles
        au.email::TEXT,
        au.phone::TEXT,
        p.username,
        COALESCE(p.role, 'user') as role, -- Default to user if auth missing
        p.first_name,
        p.last_name,
        p.full_name,
        p.image_uri,
        p.image_uri as avatar_url,
        COALESCE(p.organization_id, h.organization_id) as organization_id,
        o.name as organization_name,
        p.provider_type,
        p.bvn_verified,
        p.display_id,
        COALESCE(au.created_at, p.created_at) as created_at,
        au.last_sign_in_at,
        -- Compatibility
        p.role as profile_role,
        p.username as profile_username,
        p.first_name as profile_first_name,
        p.last_name as profile_last_name,
        p.full_name as profile_full_name,
        p.image_uri as profile_image_uri,
        p.image_uri as profile_avatar_url,
        COALESCE(p.organization_id, h.organization_id) as profile_organization_id,
        o.name as profile_organization_name,
        p.provider_type as profile_provider_type,
        p.bvn_verified as profile_bvn_verified,
        p.display_id as profile_display_id
    FROM public.profiles p
    FULL OUTER JOIN auth.users au ON p.id = au.id
    LEFT JOIN public.hospitals h ON p.id = h.org_admin_id
    LEFT JOIN public.organizations o ON (p.organization_id = o.id OR h.organization_id = o.id)
    WHERE 
        (p_organization_id IS NULL OR 
         p.organization_id = p_organization_id OR 
         h.organization_id = p_organization_id)
    ORDER BY COALESCE(au.created_at, p.created_at) DESC;
END;
$$;

GRANT EXECUTE ON FUNCTION public.get_all_auth_users(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_all_auth_users(UUID) TO service_role;

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260216222222_test_integrity.sql
-- ----------------------------------------------------------------------------

-- Database Integrity & Sanity Check
-- Run this script to detect silent issues like Orphaned Records, Missing RLS Policies, or Data Mismatches.

BEGIN;

DO $$
DECLARE
    v_users_count INT;
    v_profiles_count INT;
    v_missing_profiles INT;
    v_tables_with_rls_no_policy INT;
    v_table_name TEXT;
BEGIN
    RAISE NOTICE '----------------------------------------------------------------';
    RAISE NOTICE 'RUNNING INTEGRITY CHECKS...';
    RAISE NOTICE '----------------------------------------------------------------';

    ----------------------------------------------------------------------------
    -- 1. Check for Orphaned Users (Auth Users without Profiles)
    ----------------------------------------------------------------------------
    SELECT COUNT(*) INTO v_users_count FROM auth.users;
    SELECT COUNT(*) INTO v_profiles_count FROM public.profiles;
    
    SELECT COUNT(*) INTO v_missing_profiles
    FROM auth.users au
    LEFT JOIN public.profiles p ON au.id = p.id
    WHERE p.id IS NULL;

    IF v_missing_profiles > 0 THEN
        RAISE WARNING 'âš ï¸ Found % Auth Users without Profiles! (Orphaned Users)', v_missing_profiles;
    ELSE
        RAISE NOTICE 'âœ… All Auth Users have Profiles.';
    END IF;

    ----------------------------------------------------------------------------
    -- 2. Check for Missing RLS Policies on Protected Tables
    ----------------------------------------------------------------------------
    -- Tables with RLS enabled but ZERO policies (Data will be hidden from everyone except superuser)
    SELECT COUNT(*) INTO v_tables_with_rls_no_policy
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE c.relrowsecurity = true
    AND n.nspname = 'public'
    AND NOT EXISTS (
        SELECT 1 FROM pg_policy p WHERE p.polrelid = c.oid
    );

    IF v_tables_with_rls_no_policy > 0 THEN
        RAISE WARNING 'âš ï¸ Found % tables with RLS enabled but NO policies! (Data is effectively hidden)', v_tables_with_rls_no_policy;
        -- Optional: List them
        FOR v_table_name IN 
            SELECT relname FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace WHERE c.relrowsecurity = true AND n.nspname = 'public' AND NOT EXISTS (SELECT 1 FROM pg_policy p WHERE p.polrelid = c.oid)
        LOOP
            RAISE WARNING '   - Table: %', v_table_name;
        END LOOP;
    ELSE
        RAISE NOTICE 'âœ… All RLS-enabled tables have at least one policy.';
    END IF;

    ----------------------------------------------------------------------------
    -- 3. Room Pricing Check
    ----------------------------------------------------------------------------
    -- If room_pricing is empty but service_pricing has data, it might indicate a regression
    IF (SELECT COUNT(*) FROM public.room_pricing) = 0 THEN
        RAISE WARNING 'âš ï¸ room_pricing table is empty! Check if seed data was applied.';
    END IF;

    RAISE NOTICE '----------------------------------------------------------------';
    RAISE NOTICE 'INTEGRITY CHECKS COMPLETE.';
    RAISE NOTICE '----------------------------------------------------------------';
END;
$$;


