-- Source: 20260217082000_fix_cost_rpc_overload.sql
-- ----------------------------------------------------------------------------

-- Migration: Fix calculate_emergency_cost overload
-- Problem: Old 5-param version and new 6-param version both exist, 
--          causing PostgREST ambiguity. Drop old, keep new with service_fee.

-- Drop the OLD overload (5 params: TEXT, DECIMAL, BOOLEAN, UUID, UUID)
DROP FUNCTION IF EXISTS public.calculate_emergency_cost(TEXT, DECIMAL, BOOLEAN, UUID, UUID);

-- Drop any lingering version to be safe
DROP FUNCTION IF EXISTS public.calculate_emergency_cost(TEXT, DECIMAL, BOOLEAN, UUID, UUID, UUID);

-- Recreate the SINGLE canonical version with service fee included
CREATE OR REPLACE FUNCTION public.calculate_emergency_cost(
    p_service_type TEXT,
    p_distance DECIMAL DEFAULT 0,
    p_is_urgent BOOLEAN DEFAULT false,
    p_hospital_id UUID DEFAULT NULL,
    p_room_id UUID DEFAULT NULL,
    p_ambulance_id UUID DEFAULT NULL
)
RETURNS TABLE (
    base_cost DECIMAL,
    distance_surcharge DECIMAL,
    urgency_surcharge DECIMAL,
    service_fee DECIMAL,
    total_cost DECIMAL,
    breakdown JSONB
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_base_cost DECIMAL := 0;
    v_distance_surcharge DECIMAL := 0;
    v_urgency_surcharge DECIMAL := 0;
    v_service_fee DECIMAL := 0;
    v_subtotal DECIMAL := 0;
    v_total_cost DECIMAL := 0;
    v_breakdown JSONB := '[]'::jsonb;
    v_service_name TEXT;
    v_fee_rate DECIMAL := 0.025; -- 2.5%
BEGIN
    -- 1. Determine Base Cost
    -- Hierarchy: Room Override > Ambulance Override > Hospital/Org Pricing > Fallback
    
    IF p_service_type IN ('bed', 'bed_booking') AND p_room_id IS NOT NULL THEN
        SELECT base_price, room_type INTO v_base_cost, v_service_name
        FROM hospital_rooms
        WHERE id = p_room_id;
    END IF;

    -- Ambulance override
    IF v_base_cost IS NULL AND p_service_type = 'ambulance' AND p_ambulance_id IS NOT NULL THEN
        -- Try service_pricing first (when ambulance card ID = service_pricing ID)
        SELECT sp.base_price, sp.service_name INTO v_base_cost, v_service_name
        FROM service_pricing sp WHERE sp.id = p_ambulance_id AND sp.is_active = true;
        
        -- Fallback to ambulances table
        IF v_base_cost IS NULL THEN
            SELECT a.base_price INTO v_base_cost FROM ambulances a WHERE a.id = p_ambulance_id;
            IF v_base_cost IS NOT NULL THEN v_service_name := 'Ambulance Service'; END IF;
        END IF;
    END IF;

    -- Hospital/Org scoped pricing
    IF v_base_cost IS NULL OR v_base_cost = 0 THEN
        SELECT sp.base_price, sp.service_name 
        INTO v_base_cost, v_service_name
        FROM service_pricing sp
        LEFT JOIN hospitals h ON h.id = p_hospital_id
        WHERE sp.service_type = p_service_type 
          AND sp.is_active = true
          AND (
            sp.hospital_id = p_hospital_id OR 
            sp.organization_id = h.organization_id OR 
            (sp.hospital_id IS NULL AND sp.organization_id IS NULL)
          )
        ORDER BY 
          (sp.hospital_id = p_hospital_id) DESC, 
          (sp.organization_id = h.organization_id) DESC,
          sp.hospital_id DESC NULLS LAST,
          sp.organization_id DESC NULLS LAST
        LIMIT 1;
    END IF;

    -- Hardcoded fallbacks
    IF v_base_cost IS NULL OR v_base_cost = 0 THEN
        IF p_service_type = 'ambulance' THEN v_base_cost := 150.00; v_service_name := 'Ambulance Service';
        ELSIF p_service_type = 'consultation' THEN v_base_cost := 100.00; v_service_name := 'Consultation';
        ELSIF p_service_type IN ('bed_booking', 'bed') THEN v_base_cost := 200.00; v_service_name := 'Bed Booking';
        ELSE v_base_cost := 100.00; v_service_name := 'Standard Service';
        END IF;
    END IF;

    -- Base to breakdown
    v_breakdown := v_breakdown || jsonb_build_object(
        'name', COALESCE(v_service_name, 'Base Service'), 
        'cost', v_base_cost, 
        'type', 'base'
    );

    -- 2. Distance Surcharge (> 5km, $2/km)
    IF p_distance > 5 THEN
        v_distance_surcharge := ROUND((p_distance - 5) * 2.00, 2);
        v_breakdown := v_breakdown || jsonb_build_object(
            'name', 'Distance Surcharge', 
            'cost', v_distance_surcharge, 
            'type', 'distance'
        );
    END IF;

    -- 3. Urgency Surcharge
    IF p_is_urgent THEN
        v_urgency_surcharge := 25.00;
        v_breakdown := v_breakdown || jsonb_build_object(
            'name', 'Urgency Surcharge', 
            'cost', v_urgency_surcharge, 
            'type', 'urgency'
        );
    END IF;

    -- 4. Subtotal + Service Fee
    v_subtotal := v_base_cost + v_distance_surcharge + v_urgency_surcharge;
    v_service_fee := ROUND(v_subtotal * v_fee_rate, 2);

    v_breakdown := v_breakdown || jsonb_build_object(
        'name', 'Service Fee (2.5%)',
        'cost', v_service_fee,
        'type', 'fee'
    );

    -- 5. Total
    v_total_cost := v_subtotal + v_service_fee;

    RETURN QUERY SELECT 
        v_base_cost,
        v_distance_surcharge,
        v_urgency_surcharge,
        v_service_fee,
        v_total_cost,
        v_breakdown;
END;
$$;

-- Permissions
GRANT EXECUTE ON FUNCTION public.calculate_emergency_cost(TEXT, DECIMAL, BOOLEAN, UUID, UUID, UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION public.calculate_emergency_cost(TEXT, DECIMAL, BOOLEAN, UUID, UUID, UUID) TO service_role;

NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260217083000_atomic_payment_emergency_v2.sql
-- ----------------------------------------------------------------------------

-- Migration: Atomic Emergency Request with Payment (Corrected Order)
-- Order: Payment Stub (no emergency_request_id) â†’ Emergency Request â†’ Link Payment
-- This respects the FK constraint: payments.emergency_request_id â†’ emergency_requests.id

DROP FUNCTION IF EXISTS public.create_emergency_with_payment(UUID, JSONB, JSONB);

CREATE OR REPLACE FUNCTION public.create_emergency_with_payment(
    p_user_id UUID,
    p_request_data JSONB,
    p_payment_data JSONB
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_request_id UUID;
    v_payment_id UUID;
    v_hospital_id UUID;
    v_organization_id UUID;
    v_base_amount NUMERIC;
    v_total_amount NUMERIC;
    v_currency TEXT;
    v_payment_method TEXT;
    v_fee_rate NUMERIC;
    v_calculated_fee NUMERIC;
    v_wallet_id UUID;
    v_wallet_balance NUMERIC;
    v_main_wallet_id UUID;
    v_display_id TEXT;
    v_hospital_name TEXT;
BEGIN
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 1. EXTRACT & VALIDATE
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    v_hospital_id := (p_request_data->>'hospital_id')::UUID;
    v_base_amount := COALESCE((p_payment_data->>'base_amount')::NUMERIC, 0);
    v_total_amount := COALESCE((p_payment_data->>'total_amount')::NUMERIC, 0);
    v_currency := COALESCE(p_payment_data->>'currency', 'USD');
    v_payment_method := COALESCE(p_payment_data->>'method', 'cash');
    v_display_id := COALESCE(p_request_data->>'request_id', 'REQ-' || floor(extract(epoch from now())));

    IF v_hospital_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Hospital ID is required');
    END IF;

    -- Resolve Organization
    SELECT h.organization_id, h.name 
    INTO v_organization_id, v_hospital_name 
    FROM public.hospitals h WHERE h.id = v_hospital_id;
    
    IF v_organization_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Hospital has no linked organization');
    END IF;

    -- Get fee rate
    SELECT COALESCE(o.ivisit_fee_percentage, 2.5) INTO v_fee_rate 
    FROM public.organizations o WHERE o.id = v_organization_id;
    v_fee_rate := COALESCE(v_fee_rate, 2.5);

    -- Calculate fee on base amount
    v_calculated_fee := ROUND((v_base_amount * v_fee_rate) / 100, 2);

    -- If total wasn't passed, calculate it
    IF v_total_amount = 0 THEN
        v_total_amount := v_base_amount + v_calculated_fee;
    END IF;

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 2. PAYMENT VALIDATION (Pre-flight check)
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    IF v_payment_method = 'cash' THEN
        -- Org must have enough to cover the fee (they keep the cash)
        SELECT ow.id, ow.balance INTO v_wallet_id, v_wallet_balance
        FROM public.organization_wallets ow
        WHERE ow.organization_id = v_organization_id;

        IF v_wallet_id IS NULL THEN
            RETURN jsonb_build_object('success', false, 'error', 'Organization wallet not initialized');
        END IF;

        IF v_wallet_balance < v_calculated_fee THEN
            RETURN jsonb_build_object(
                'success', false, 
                'error', 'Organization insufficient balance for platform fee',
                'code', 'ORG_INSUFFICIENT_FUNDS',
                'required', v_calculated_fee,
                'available', v_wallet_balance
            );
        END IF;
    END IF;

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 3. CREATE PAYMENT STUB (no emergency_request_id yet)
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    INSERT INTO public.payments (
        user_id,
        amount,
        currency,
        status,
        payment_method_id,
        emergency_request_id, -- NULL for now, linked after emergency creation
        organization_id,
        metadata
    ) VALUES (
        p_user_id,
        v_total_amount,
        v_currency,
        'pending', -- Start as pending, trigger fires on status change
        v_payment_method,
        NULL, -- â† No FK violation
        v_organization_id,
        jsonb_build_object(
            'base_amount', v_base_amount,
            'fee_amount', v_calculated_fee,
            'fee_rate', v_fee_rate,
            'source', 'create_emergency_with_payment',
            'hospital_id', v_hospital_id::text
        )
    )
    RETURNING id INTO v_payment_id;

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 4. PROCESS FEE (Cash: deduct from org, credit platform)
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    IF v_payment_method = 'cash' THEN
        -- Deduct fee from org wallet
        UPDATE public.organization_wallets
        SET balance = balance - v_calculated_fee, updated_at = NOW()
        WHERE id = v_wallet_id;

        -- Record org debit
        INSERT INTO public.wallet_ledger (
            wallet_type, wallet_id, organization_id, amount, 
            transaction_type, description, reference_id, reference_type
        ) VALUES (
            'organization', v_wallet_id, v_organization_id, -v_calculated_fee, 
            'debit', 'Platform Fee (Cash Job)', v_payment_id, 'payment'
        );

        -- Credit platform wallet
        SELECT id INTO v_main_wallet_id FROM public.ivisit_main_wallet LIMIT 1;
        IF v_main_wallet_id IS NOT NULL THEN
            UPDATE public.ivisit_main_wallet 
            SET balance = balance + v_calculated_fee, last_updated = NOW() 
            WHERE id = v_main_wallet_id;

            INSERT INTO public.wallet_ledger (
                wallet_type, wallet_id, amount, 
                transaction_type, description, reference_id, reference_type
            ) VALUES (
                'main', v_main_wallet_id, v_calculated_fee, 
                'credit', 'Fee from Cash Job', v_payment_id, 'payment'
            );
        END IF;

        -- Mark payment completed (fee already handled manually above)
        UPDATE public.payments 
        SET status = 'completed',
            metadata = metadata || '{"ledger_credited": true}'::jsonb,
            updated_at = NOW()
        WHERE id = v_payment_id;
    END IF;

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 5. CREATE EMERGENCY REQUEST
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    v_request_id := gen_random_uuid();

    INSERT INTO public.emergency_requests (
        id,
        user_id,
        hospital_id,
        hospital_name,
        service_type,
        specialty,
        status,
        patient_location,
        request_id,
        patient_snapshot,
        total_cost,
        payment_status,
        payment_method_id,
        created_at,
        updated_at
    )
    VALUES (
        v_request_id,
        p_user_id,
        v_hospital_id,
        v_hospital_name,
        p_request_data->>'service_type',
        p_request_data->>'specialty',
        'in_progress',
        CASE 
            WHEN p_request_data->>'patient_location' IS NOT NULL 
            THEN (p_request_data->>'patient_location')
            ELSE NULL
        END,
        v_display_id,
        CASE 
            WHEN p_request_data->'patient_snapshot' IS NOT NULL 
            THEN p_request_data->'patient_snapshot'
            ELSE NULL
        END,
        v_total_amount,
        'completed',
        v_payment_method,
        NOW(),
        NOW()
    );

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 6. LINK PAYMENT â†’ EMERGENCY REQUEST
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    UPDATE public.payments 
    SET emergency_request_id = v_request_id,
        updated_at = NOW()
    WHERE id = v_payment_id;

    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    -- 7. RETURN SUCCESS
    -- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
    RETURN jsonb_build_object(
        'success', true, 
        'request_id', v_request_id, 
        'payment_id', v_payment_id,
        'display_id', v_display_id,
        'fee_deducted', v_calculated_fee,
        'total_amount', v_total_amount
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;

