-- ----------------------------------------------------------------------------
-- Source: 20260217160000_dispatch_fix.sql
-- ----------------------------------------------------------------------------

-- ============================================================================
-- Migration: Dispatch Fix â€” Auto-Assignment, Visit Enrichment, Notifications
-- Date: 2026-02-17
-- Backup: supabase/backups/pre_dispatch_fix_20260217/
-- ============================================================================
-- FIXES:
-- 1. auto_assign_driver: Uses COALESCE(profile_id, driver_id), removes
--    provider_type filter, fires on INSERT+UPDATE with status guard
-- 2. Visit sync: Enriches visit with hospital cost/address/phone/image
-- 3. Notification: Uses hospital_name instead of patient_location (geography)
-- 4. ETA: Populates estimated_arrival from hospital.emergency_wait_time_minutes
-- 5. Distance floor: Prevents division by zero in wait time math
-- ============================================================================

BEGIN;

-- ============================================================================
-- 1. FIX AUTO-ASSIGN DRIVER
-- ============================================================================
-- Problems fixed:
-- A. JOIN used profile_id but data uses driver_id â†’ COALESCE both
-- B. provider_type = 'ambulance' filter too strict â†’ removed
-- C. Fires on INSERT only â†’ now INSERT + UPDATE
-- D. No status guard â†’ only assigns when status IN ('in_progress','accepted')

CREATE OR REPLACE FUNCTION public.auto_assign_driver()
RETURNS TRIGGER AS $$
DECLARE
    v_ambulance_id TEXT;
    v_driver_profile_id UUID;
    v_driver_name TEXT;
    v_driver_phone TEXT;
    v_ambulance_type TEXT;
    v_vehicle_number TEXT;
    v_hospital_wait_minutes INTEGER;
    v_eta_text TEXT;
BEGIN
    -- Guard: Only assign ambulance requests that are ready for dispatch
    IF NEW.service_type != 'ambulance' THEN
        RETURN NEW;
    END IF;

    -- Guard: Only assign when status is actionable (not pending_approval)
    IF NEW.status NOT IN ('in_progress', 'accepted') THEN
        RETURN NEW;
    END IF;

    -- Guard: Already assigned
    IF NEW.ambulance_id IS NOT NULL AND NEW.responder_id IS NOT NULL THEN
        RETURN NEW;
    END IF;

    -- Find available ambulance at this hospital
    -- Uses COALESCE(profile_id, driver_id) to handle both column conventions
    SELECT
        a.id,
        COALESCE(a.profile_id, a.driver_id),
        p.full_name,
        p.phone,
        a.type,
        a.vehicle_number
    INTO
        v_ambulance_id,
        v_driver_profile_id,
        v_driver_name,
        v_driver_phone,
        v_ambulance_type,
        v_vehicle_number
    FROM public.ambulances a
    LEFT JOIN public.profiles p ON p.id = COALESCE(a.profile_id, a.driver_id)
    WHERE a.status = 'available'
      AND a.hospital_id::text = NEW.hospital_id::text
    ORDER BY a.created_at ASC
    LIMIT 1;

    -- If no ambulance found, exit silently (console manual dispatch remains available)
    IF v_ambulance_id IS NULL THEN
        RETURN NEW;
    END IF;

    -- Get hospital wait time for ETA
    SELECT COALESCE(h.emergency_wait_time_minutes, 10)
    INTO v_hospital_wait_minutes
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    -- Ensure minimum wait time (prevents 0-minute ETA edge case)
    IF v_hospital_wait_minutes IS NULL OR v_hospital_wait_minutes < 1 THEN
        v_hospital_wait_minutes := 5;
    END IF;

    v_eta_text := v_hospital_wait_minutes || ' mins';

    -- Update the emergency request with responder details
    UPDATE public.emergency_requests
    SET
        ambulance_id = v_ambulance_id,
        responder_id = v_driver_profile_id,
        responder_name = COALESCE(v_driver_name, 'Emergency Responder'),
        responder_phone = v_driver_phone,
        responder_vehicle_type = COALESCE(v_ambulance_type, 'Basic'),
        responder_vehicle_plate = v_vehicle_number,
        estimated_arrival = v_eta_text
    WHERE id = NEW.id;

    -- Mark ambulance as on_trip
    UPDATE public.ambulances
    SET status = 'on_trip', current_call = NEW.id::text
    WHERE id = v_ambulance_id;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Rebind trigger: fires on both INSERT and UPDATE
DROP TRIGGER IF EXISTS on_emergency_request_auto_assign_driver ON public.emergency_requests;
CREATE TRIGGER on_emergency_request_auto_assign_driver
    AFTER INSERT OR UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.auto_assign_driver();

-- ============================================================================
-- 2. VISIT ENRICHMENT TRIGGER
-- ============================================================================
-- When emergency_requests update, sync key fields to the linked visit record
-- Enriches with hospital metadata (address, phone, image, cost)

CREATE OR REPLACE FUNCTION public.sync_emergency_to_visit()
RETURNS TRIGGER AS $$
DECLARE
    v_hospital_address TEXT;
    v_hospital_phone TEXT;
    v_hospital_image TEXT;
BEGIN
    -- Only sync if there's a meaningful change
    IF (TG_OP = 'UPDATE' AND OLD.status = NEW.status 
        AND OLD.ambulance_id IS NOT DISTINCT FROM NEW.ambulance_id
        AND OLD.responder_name IS NOT DISTINCT FROM NEW.responder_name
        AND OLD.estimated_arrival IS NOT DISTINCT FROM NEW.estimated_arrival
        AND OLD.total_cost IS NOT DISTINCT FROM NEW.total_cost) THEN
        RETURN NEW;
    END IF;

    -- Fetch hospital metadata for enrichment
    SELECT 
        COALESCE(h.google_address, h.address),
        COALESCE(h.google_phone, h.phone),
        h.image
    INTO v_hospital_address, v_hospital_phone, v_hospital_image
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    -- Update the visit record (shares same ID as emergency request)
    UPDATE public.visits
    SET
        status = CASE NEW.status
            WHEN 'pending_approval' THEN 'pending'
            WHEN 'payment_declined' THEN 'cancelled'
            WHEN 'in_progress' THEN 'upcoming'
            WHEN 'accepted' THEN 'upcoming'
            WHEN 'arrived' THEN 'in-progress'
            WHEN 'completed' THEN 'completed'
            WHEN 'cancelled' THEN 'cancelled'
            ELSE COALESCE(visits.status, 'upcoming')
        END,
        cost = COALESCE(NEW.total_cost::text, visits.cost),
        address = COALESCE(v_hospital_address, visits.address),
        phone = COALESCE(v_hospital_phone, visits.phone),
        image = COALESCE(v_hospital_image, visits.image),
        updated_at = NOW()
    WHERE id = NEW.id;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_emergency_sync_visit ON public.emergency_requests;
CREATE TRIGGER on_emergency_sync_visit
    AFTER INSERT OR UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.sync_emergency_to_visit();

-- ============================================================================
-- 3. FIX NOTIFICATION MESSAGE (patient_location is GEOGRAPHY, not TEXT)
-- ============================================================================

CREATE OR REPLACE FUNCTION public.notify_emergency_events()
RETURNS TRIGGER AS $$
DECLARE
    v_org_id UUID;
    v_hospital_name TEXT;
    v_admin_id UUID;
    v_notification_type TEXT;
    v_title TEXT;
    v_message TEXT;
    v_priority TEXT := 'normal';
BEGIN
    -- A. RESOLVE CONTEXT (Hospital & Organization)
    SELECT h.organization_id, h.name INTO v_org_id, v_hospital_name
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    -- B. NEW REQUEST CREATED (INSERT)
    IF (TG_OP = 'INSERT') THEN
        v_notification_type := 'emergency';
        v_title := 'ðŸš¨ New ' || initcap(NEW.service_type) || ' Request';
        -- FIX: Use hospital_name instead of patient_location (which is GEOGRAPHY)
        v_message := 'A new emergency request has been initiated at ' 
                     || COALESCE(v_hospital_name, 'an iVisit partner hospital') || '.';
        v_priority := 'high';

        -- Notify ALL Administrators (Org Admins & Platform Admins)
        FOR v_admin_id IN 
            SELECT id FROM public.profiles 
            WHERE (
                organization_id = v_org_id
                OR organization_id::text = NEW.hospital_id::text
                OR role = 'admin'
            )
            AND role IN ('org_admin', 'admin')
            AND id != NEW.user_id
        LOOP
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                v_admin_id, v_notification_type, v_title, v_message, v_priority, 
                NEW.id, jsonb_build_object('request_id', NEW.id, 'service_type', NEW.service_type)
            );
        END LOOP;

    -- C. STATUS OR PAYMENT UPDATES (UPDATE)
    ELSIF (TG_OP = 'UPDATE') THEN
        
        -- 1. PAYMENT APPROVAL (User Notification)
        IF (OLD.payment_status IS DISTINCT FROM NEW.payment_status AND NEW.payment_status = 'completed') THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'payment', 'âœ… Payment Approved', 
                'Your cash payment for ' || COALESCE(v_hospital_name, 'the hospital') || ' has been confirmed. Help is prioritized.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 2. PAYMENT DECLINED (User Notification)
        IF (OLD.payment_status IS DISTINCT FROM NEW.payment_status AND NEW.payment_status = 'declined') THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'payment', 'âŒ Payment Declined', 
                'Your cash payment for ' || COALESCE(v_hospital_name, 'the hospital') || ' was declined. Please try a different payment method.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 3. EMERGENCY ACCEPTED â€” Responder assigned (User Notification)
        IF (OLD.status IS DISTINCT FROM NEW.status AND NEW.status IN ('accepted', 'assigned')) THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'emergency', 'ðŸš‘ Help is On The Way', 
                COALESCE(v_hospital_name, 'The hospital') || ' has accepted your request. View details for live tracking.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id, 'status', NEW.status)
            );
        END IF;

        -- 4. EMERGENCY COMPLETED (User Notification)
        IF (OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'completed') THEN
             INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'emergency', 'ðŸ Service Completed', 
                'Your emergency request has been successfully closed. Thank you for choosing iVisit.', 
                'normal', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 5. RESPONDER ASSIGNED â€” Notify driver/provider
        IF (OLD.responder_id IS DISTINCT FROM NEW.responder_id AND NEW.responder_id IS NOT NULL) THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.responder_id, 'emergency', 'ðŸš¨ New Mission Assigned', 
                'You have been dispatched to ' || COALESCE(v_hospital_name, 'a location') || '. Check details now.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id, 'service_type', NEW.service_type)
            );
        END IF;

    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Trigger already bound from previous migration (on_emergency_request_activity)
-- Re-bind to be safe
DROP TRIGGER IF EXISTS on_emergency_request_activity ON public.emergency_requests;
CREATE TRIGGER on_emergency_request_activity
    AFTER INSERT OR UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.notify_emergency_events();

-- ============================================================================
-- 4. ENSURE driver_id COLUMN EXISTS ON AMBULANCES
-- ============================================================================
-- Some ambulances have data in driver_id but the column may not be in schema
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
        AND table_name = 'ambulances' 
        AND column_name = 'driver_id'
    ) THEN
        ALTER TABLE public.ambulances ADD COLUMN driver_id UUID;
    END IF;
END $$;

-- ============================================================================
-- 5. GRANT PERMISSIONS
-- ============================================================================
GRANT EXECUTE ON FUNCTION public.auto_assign_driver() TO authenticated;
GRANT EXECUTE ON FUNCTION public.sync_emergency_to_visit() TO authenticated;
GRANT EXECUTE ON FUNCTION public.notify_emergency_events() TO authenticated;

-- Refresh schema cache
NOTIFY pgrst, 'reload schema';

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217170000_backfill_active_emergency.sql
-- ----------------------------------------------------------------------------

-- ============================================================================
-- One-time backfill: Activate current ongoing emergency request
-- Target: ec72b8c4-6bce-414b-b353-0eee10540369
-- Purpose: The auto_assign_driver trigger was deployed AFTER this request
--          was created. This migration "touches" the request so the trigger
--          fires and assigns the ambulance + responder + ETA.
-- ============================================================================

BEGIN;

-- Step 1: Approve cash payment if still pending
--         This moves status from 'pending_approval' â†’ 'in_progress'
--         which is one of the statuses that auto_assign_driver responds to.
DO $$
DECLARE
    v_req_id UUID := 'ec72b8c4-6bce-414b-b353-0eee10540369'::uuid;
    v_current_status TEXT;
    v_payment_status TEXT;
    v_ambulance_id TEXT;
BEGIN
    -- Get current state
    SELECT status, payment_status, ambulance_id
    INTO v_current_status, v_payment_status, v_ambulance_id
    FROM public.emergency_requests
    WHERE id = v_req_id;

    -- Log current state
    RAISE NOTICE 'Current state: status=%, payment=%, ambulance=%',
        v_current_status, v_payment_status, v_ambulance_id;

    -- If no request found, exit
    IF v_current_status IS NULL THEN
        RAISE NOTICE 'Emergency request % not found, skipping backfill.', v_req_id;
        RETURN;
    END IF;

    -- Case 1: pending_approval â†’ approve and move to in_progress
    IF v_current_status = 'pending_approval' THEN
        RAISE NOTICE 'Approving cash payment and moving to in_progress...';
        UPDATE public.emergency_requests
        SET
            status = 'in_progress',
            payment_status = 'completed',
            updated_at = NOW()
        WHERE id = v_req_id;

        -- Also update the payment record
        UPDATE public.payments
        SET
            status = 'completed',
            updated_at = NOW()
        WHERE emergency_request_id = v_req_id
          AND status != 'completed';

    -- Case 2: Already in_progress/accepted but no ambulance assigned
    ELSIF v_current_status IN ('in_progress', 'accepted') AND v_ambulance_id IS NULL THEN
        RAISE NOTICE 'Already in_progress but no ambulance - re-triggering assignment...';
        -- Touch the row to re-fire the trigger
        UPDATE public.emergency_requests
        SET updated_at = NOW()
        WHERE id = v_req_id;

    -- Case 3: Already has ambulance - just ensure visit is enriched
    ELSIF v_ambulance_id IS NOT NULL THEN
        RAISE NOTICE 'Ambulance already assigned (%), touching to enrich visit...', v_ambulance_id;
        UPDATE public.emergency_requests
        SET updated_at = NOW()
        WHERE id = v_req_id;

    -- Case 4: Any other status
    ELSE
        RAISE NOTICE 'Status is %. Moving to in_progress to trigger assignment.', v_current_status;
        UPDATE public.emergency_requests
        SET
            status = 'in_progress',
            updated_at = NOW()
        WHERE id = v_req_id;
    END IF;
END $$;

-- Step 2: Verify the result
DO $$
DECLARE
    v_status TEXT;
    v_ambulance TEXT;
    v_responder TEXT;
    v_responder_name TEXT;
    v_eta TEXT;
BEGIN
    SELECT status, ambulance_id, responder_id, responder_name, estimated_arrival
    INTO v_status, v_ambulance, v_responder, v_responder_name, v_eta
    FROM public.emergency_requests
    WHERE id = 'ec72b8c4-6bce-414b-b353-0eee10540369'::uuid;

    RAISE NOTICE '=== BACKFILL RESULT ===';
    RAISE NOTICE 'Status:         %', v_status;
    RAISE NOTICE 'Ambulance ID:   %', v_ambulance;
    RAISE NOTICE 'Responder ID:   %', v_responder;
    RAISE NOTICE 'Responder Name: %', v_responder_name;
    RAISE NOTICE 'ETA:            %', v_eta;
    RAISE NOTICE '======================';
END $$;

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217170100_discover_state.sql
-- ----------------------------------------------------------------------------

-- Discovery: dump emergency state into a temp table then select it
-- Using a simpler approach to avoid NOTICE truncation

BEGIN;

-- Create a temporary result log table
CREATE TABLE IF NOT EXISTS public._debug_log (
    line_num SERIAL,
    category TEXT,
    field TEXT,
    val TEXT
);
TRUNCATE public._debug_log;

-- Dump emergency requests
INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'id', id::text FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'status', status FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'payment_status', payment_status FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'service_type', service_type FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'hospital_name', hospital_name FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'ambulance_id', ambulance_id::text FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'responder_name', responder_name FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'emergency', 'estimated_arrival', estimated_arrival FROM public.emergency_requests ORDER BY created_at DESC LIMIT 5;

-- Dump ambulances
INSERT INTO public._debug_log (category, field, val)
SELECT 'ambulance', 'id', id::text FROM public.ambulances ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'ambulance', 'status', status FROM public.ambulances ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'ambulance', 'hospital_id', hospital_id::text FROM public.ambulances ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'ambulance', 'driver', COALESCE(profile_id, driver_id)::text FROM public.ambulances ORDER BY created_at DESC LIMIT 5;

INSERT INTO public._debug_log (category, field, val)
SELECT 'ambulance', 'vehicle_number', vehicle_number FROM public.ambulances ORDER BY created_at DESC LIMIT 5;

-- Summary
DO $$
DECLARE
    rec RECORD;
BEGIN
    FOR rec IN SELECT * FROM public._debug_log ORDER BY category, line_num LOOP
        RAISE NOTICE '[%] %: %', rec.category, rec.field, rec.val;
    END LOOP;
END $$;

-- Cleanup
DROP TABLE IF EXISTS public._debug_log;

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217170200_hotfix_current_call_jsonb.sql
-- ----------------------------------------------------------------------------

-- ============================================================================
-- Hotfix: current_call column is JSONB, not TEXT
-- Also backfill the active emergency with ambulance assignment
-- ============================================================================

BEGIN;

-- Fix: Cast current_call to jsonb properly
CREATE OR REPLACE FUNCTION public.auto_assign_driver()
RETURNS TRIGGER AS $$
DECLARE
    v_ambulance_id TEXT;
    v_driver_profile_id UUID;
    v_driver_name TEXT;
    v_driver_phone TEXT;
    v_ambulance_type TEXT;
    v_vehicle_number TEXT;
    v_hospital_wait_minutes INTEGER;
    v_eta_text TEXT;
BEGIN
    -- Guard: Only assign ambulance requests that are ready for dispatch
    IF NEW.service_type != 'ambulance' THEN
        RETURN NEW;
    END IF;

    -- Guard: Only assign when status is actionable (not pending_approval)
    IF NEW.status NOT IN ('in_progress', 'accepted') THEN
        RETURN NEW;
    END IF;

    -- Guard: Already assigned
    IF NEW.ambulance_id IS NOT NULL AND NEW.responder_id IS NOT NULL THEN
        RETURN NEW;
    END IF;

    -- Find available ambulance at this hospital
    SELECT
        a.id,
        COALESCE(a.profile_id, a.driver_id),
        p.full_name,
        p.phone,
        a.type,
        a.vehicle_number
    INTO
        v_ambulance_id,
        v_driver_profile_id,
        v_driver_name,
        v_driver_phone,
        v_ambulance_type,
        v_vehicle_number
    FROM public.ambulances a
    LEFT JOIN public.profiles p ON p.id = COALESCE(a.profile_id, a.driver_id)
    WHERE a.status = 'available'
      AND a.hospital_id::text = NEW.hospital_id::text
    ORDER BY a.created_at ASC
    LIMIT 1;

    -- If no ambulance found, exit silently
    IF v_ambulance_id IS NULL THEN
        RETURN NEW;
    END IF;

    -- Get hospital wait time for ETA
    SELECT COALESCE(h.emergency_wait_time_minutes, 10)
    INTO v_hospital_wait_minutes
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    IF v_hospital_wait_minutes IS NULL OR v_hospital_wait_minutes < 1 THEN
        v_hospital_wait_minutes := 5;
    END IF;

    v_eta_text := v_hospital_wait_minutes || ' mins';

    -- Update the emergency request with responder details
    UPDATE public.emergency_requests
    SET
        ambulance_id = v_ambulance_id,
        responder_id = v_driver_profile_id,
        responder_name = COALESCE(v_driver_name, 'Emergency Responder'),
        responder_phone = v_driver_phone,
        responder_vehicle_type = COALESCE(v_ambulance_type, 'Basic'),
        responder_vehicle_plate = v_vehicle_number,
        estimated_arrival = v_eta_text
    WHERE id = NEW.id;

    -- Mark ambulance as on_trip â€” cast to jsonb for current_call
    UPDATE public.ambulances
    SET status = 'on_trip', current_call = to_jsonb(NEW.id::text)
    WHERE id = v_ambulance_id;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217180000_post_completion_flow.sql
-- ----------------------------------------------------------------------------

-- ==========================================================================
-- POST-COMPLETION FLOW FIX â€” 2026-02-17
-- ==========================================================================
-- Fixes:
--   1. Auto-release ambulance back to 'available' on completion/cancellation
--   2. Enhance sync_emergency_to_visit to handle arrival notifications
--   3. Add org_admin/admin RLS policies on visits table
--   4. Cleanup: prevent duplicate visits by syncing both UUID and display-ID
-- ==========================================================================
BEGIN;

-- ============================================================================
-- 1. AMBULANCE RELEASE TRIGGER
-- ============================================================================
-- When an emergency request is completed or cancelled, release the ambulance
-- back to 'available' status and clear its current_call.

CREATE OR REPLACE FUNCTION public.release_ambulance_on_completion()
RETURNS TRIGGER AS $$
BEGIN
    -- Only fire on status change to terminal states
    IF (TG_OP = 'UPDATE' 
        AND OLD.status IS DISTINCT FROM NEW.status
        AND NEW.status IN ('completed', 'cancelled')
        AND NEW.ambulance_id IS NOT NULL) THEN
        
        UPDATE public.ambulances
        SET 
            status = 'available',
            current_call = NULL,
            updated_at = NOW()
        WHERE id = NEW.ambulance_id
          AND status = 'on_trip';
        
        RAISE NOTICE '[release_ambulance] Ambulance % released back to available (emergency % â†’ %)',
            NEW.ambulance_id, NEW.id, NEW.status;
    END IF;
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_emergency_release_ambulance ON public.emergency_requests;
CREATE TRIGGER on_emergency_release_ambulance
    AFTER UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.release_ambulance_on_completion();

-- ============================================================================
-- 2. ENHANCED VISIT SYNC â€” Handle display-ID visits too
-- ============================================================================
-- The frontend sometimes creates visits with UUID as `request_id`, and
-- the original trigger only updates visits WHERE id = NEW.id (the UUID).
-- This enhanced version also syncs any visit with request_id matching
-- the display ID, and prevents orphan rows.

CREATE OR REPLACE FUNCTION public.sync_emergency_to_visit()
RETURNS TRIGGER AS $$
DECLARE
    v_hospital_address TEXT;
    v_hospital_phone TEXT;
    v_hospital_image TEXT;
    v_visit_status TEXT;
    v_matched_count INT;
BEGIN
    -- Only sync if there's a meaningful change
    IF (TG_OP = 'UPDATE' AND OLD.status = NEW.status 
        AND OLD.ambulance_id IS NOT DISTINCT FROM NEW.ambulance_id
        AND OLD.responder_name IS NOT DISTINCT FROM NEW.responder_name
        AND OLD.estimated_arrival IS NOT DISTINCT FROM NEW.estimated_arrival
        AND OLD.total_cost IS NOT DISTINCT FROM NEW.total_cost) THEN
        RETURN NEW;
    END IF;

    -- Fetch hospital metadata for enrichment
    SELECT 
        COALESCE(h.google_address, h.address),
        COALESCE(h.google_phone, h.phone),
        h.image
    INTO v_hospital_address, v_hospital_phone, v_hospital_image
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    -- Map emergency status â†’ visit status
    v_visit_status := CASE NEW.status
        WHEN 'pending_approval' THEN 'pending'
        WHEN 'payment_declined' THEN 'cancelled'
        WHEN 'in_progress' THEN 'upcoming'
        WHEN 'accepted' THEN 'upcoming'
        WHEN 'arrived' THEN 'in-progress'
        WHEN 'completed' THEN 'completed'
        WHEN 'cancelled' THEN 'cancelled'
        ELSE 'upcoming'
    END;

    -- A. Update the canonical visit (shares UUID with emergency request)
    UPDATE public.visits
    SET
        status = v_visit_status,
        cost = COALESCE(NEW.total_cost::text, visits.cost),
        address = COALESCE(v_hospital_address, visits.address),
        phone = COALESCE(v_hospital_phone, visits.phone),
        image = COALESCE(v_hospital_image, visits.image),
        doctor = COALESCE(NEW.responder_name, visits.doctor),
        updated_at = NOW()
    WHERE id = NEW.id::text;
    
    GET DIAGNOSTICS v_matched_count = ROW_COUNT;

    -- B. Also update any visits linked by display ID (request_id column)
    --    This catches visits created by the frontend with display IDs
    IF NEW.request_id IS NOT NULL THEN
        UPDATE public.visits
        SET
            status = v_visit_status,
            cost = COALESCE(NEW.total_cost::text, visits.cost),
            address = COALESCE(v_hospital_address, visits.address),
            phone = COALESCE(v_hospital_phone, visits.phone),
            image = COALESCE(v_hospital_image, visits.image),
            doctor = COALESCE(NEW.responder_name, visits.doctor),
            updated_at = NOW()
        WHERE request_id = NEW.request_id
          AND id != NEW.id::text;  -- Don't double-update the canonical one
    END IF;

    -- C. Also catch visits where request_id = the emergency UUID
    --    (frontend sometimes stores the UUID as request_id)
    UPDATE public.visits
    SET
        status = v_visit_status,
        cost = COALESCE(NEW.total_cost::text, visits.cost),
        address = COALESCE(v_hospital_address, visits.address),
        phone = COALESCE(v_hospital_phone, visits.phone),
        image = COALESCE(v_hospital_image, visits.image),
        doctor = COALESCE(NEW.responder_name, visits.doctor),
        updated_at = NOW()
    WHERE request_id = NEW.id::text
      AND id != NEW.id::text;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Rebind
DROP TRIGGER IF EXISTS on_emergency_sync_visit ON public.emergency_requests;
CREATE TRIGGER on_emergency_sync_visit
    AFTER INSERT OR UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.sync_emergency_to_visit();

-- ============================================================================
-- 3. ENHANCED NOTIFICATIONS â€” Add Arrived + Cash Approval Required
-- ============================================================================
-- Notifications were mostly working but missing:
--   - "Ambulance Arrived" notification to admins
--   - "Cash Payment Approval Required" type for admin panel

CREATE OR REPLACE FUNCTION public.notify_emergency_events()
RETURNS TRIGGER AS $$
DECLARE
    v_org_id UUID;
    v_hospital_name TEXT;
    v_admin_id UUID;
    v_notification_type TEXT;
    v_title TEXT;
    v_message TEXT;
    v_priority TEXT := 'normal';
BEGIN
    -- A. RESOLVE CONTEXT (Hospital & Organization)
    SELECT h.organization_id, h.name INTO v_org_id, v_hospital_name
    FROM public.hospitals h
    WHERE h.id::text = NEW.hospital_id::text;

    -- B. NEW REQUEST CREATED (INSERT)
    IF (TG_OP = 'INSERT') THEN
        v_notification_type := 'emergency';
        v_title := 'ðŸš¨ New ' || initcap(COALESCE(NEW.service_type, 'Emergency')) || ' Request';
        v_message := 'A patient has requested a '
                     || initcap(COALESCE(NEW.service_type, 'service'))
                     || ' (' || COALESCE(NEW.request_id, 'N/A') || ') at '
                     || COALESCE(v_hospital_name, 'an iVisit partner hospital') || '.';
        v_priority := 'high';

        -- Check if this is a cash payment requiring approval
        IF (NEW.payment_status = 'pending' OR NEW.status = 'pending_approval') THEN
            v_title := 'Cash Payment Approval Required';
            v_message := v_message || ' This is a cash payment'
                         || CASE WHEN NEW.total_cost IS NOT NULL 
                                 THEN ', cash payment of $' || ROUND(NEW.total_cost::numeric, 2)::text
                                 ELSE '' END
                         || '. Please review and approve or decline.'
                         || E'\n\nSteps:\n1. Open emergency requests.\n2. Find request '
                         || COALESCE(NEW.request_id, NEW.id::text)
                         || E'.\n3. Review details.\n4. Tap to approve or decline.';
            v_priority := 'urgent';
        END IF;

        -- Notify ALL Administrators (Org Admins & Platform Admins)
        FOR v_admin_id IN 
            SELECT id FROM public.profiles 
            WHERE (
                organization_id = v_org_id
                OR organization_id::text = NEW.hospital_id::text
                OR role = 'admin'
            )
            AND role IN ('org_admin', 'admin')
            AND id != NEW.user_id
        LOOP
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                v_admin_id, v_notification_type, v_title, v_message, v_priority, 
                NEW.id, jsonb_build_object(
                    'request_id', NEW.id,
                    'display_id', COALESCE(NEW.request_id, ''),
                    'service_type', COALESCE(NEW.service_type, ''),
                    'requires_approval', (NEW.status = 'pending_approval')
                )
            );
        END LOOP;

    -- C. STATUS OR PAYMENT UPDATES (UPDATE)
    ELSIF (TG_OP = 'UPDATE') THEN
        
        -- 1. PAYMENT APPROVAL â†’ User, update status
        IF (OLD.payment_status IS DISTINCT FROM NEW.payment_status AND NEW.payment_status = 'completed') THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'payment', 'âœ… Payment Approved', 
                'Your cash payment for ' || COALESCE(v_hospital_name, 'the hospital') || ' has been confirmed. Help is prioritized.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 2. PAYMENT DECLINED â†’ User
        IF (OLD.payment_status IS DISTINCT FROM NEW.payment_status AND NEW.payment_status = 'declined') THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'payment', 'âŒ Payment Declined', 
                'Your cash payment for ' || COALESCE(v_hospital_name, 'the hospital') || ' was declined. Please try a different payment method.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 3. EMERGENCY IN PROGRESS / ACCEPTED â†’ User
        IF (OLD.status IS DISTINCT FROM NEW.status AND NEW.status IN ('in_progress', 'accepted', 'assigned')) THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'emergency', 'ðŸš‘ Help is On The Way', 
                COALESCE(v_hospital_name, 'The hospital') || ' has accepted your request. '
                || CASE WHEN NEW.responder_name IS NOT NULL 
                        THEN NEW.responder_name || ' is en route.' 
                        ELSE 'View details for live tracking.' END,
                'high', NEW.id, jsonb_build_object('request_id', NEW.id, 'status', NEW.status)
            );
        END IF;

        -- 4. AMBULANCE ARRIVED â†’ User + Admin
        IF (OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'arrived') THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'emergency', 'Ambulance Arrived', 
                COALESCE(NEW.responder_name, 'Your responder') || ' has arrived at your location.',
                'high', NEW.id, jsonb_build_object('request_id', NEW.id, 'status', NEW.status)
            );
            -- Also notify admins
            FOR v_admin_id IN
                SELECT id FROM public.profiles
                WHERE (organization_id = v_org_id OR role = 'admin')
                AND role IN ('org_admin', 'admin')
                AND id != NEW.user_id
            LOOP
                INSERT INTO public.notifications (
                    user_id, type, title, message, priority, target_id, metadata
                ) VALUES (
                    v_admin_id, 'emergency', 'ðŸ“ Responder Arrived',
                    COALESCE(NEW.responder_name, 'Responder') || ' has arrived for request '
                    || COALESCE(NEW.request_id, NEW.id::text) || '.',
                    'normal', NEW.id, jsonb_build_object('request_id', NEW.id, 'status', NEW.status)
                );
            END LOOP;
        END IF;

        -- 5. EMERGENCY COMPLETED â†’ User
        IF (OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'completed') THEN
             INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.user_id, 'emergency', 'ðŸ Service Completed', 
                'Your emergency request has been successfully closed. Thank you for choosing iVisit.', 
                'normal', NEW.id, jsonb_build_object('request_id', NEW.id)
            );
        END IF;

        -- 6. RESPONDER ASSIGNED â†’ Driver/Provider
        IF (OLD.responder_id IS DISTINCT FROM NEW.responder_id AND NEW.responder_id IS NOT NULL) THEN
            INSERT INTO public.notifications (
                user_id, type, title, message, priority, target_id, metadata
            ) VALUES (
                NEW.responder_id, 'emergency', 'ðŸš¨ New Mission Assigned', 
                'You have been dispatched to ' || COALESCE(v_hospital_name, 'a location') || '. Check details now.', 
                'high', NEW.id, jsonb_build_object('request_id', NEW.id, 'service_type', NEW.service_type)
            );
        END IF;

    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Rebind
DROP TRIGGER IF EXISTS on_emergency_request_activity ON public.emergency_requests;
CREATE TRIGGER on_emergency_request_activity
    AFTER INSERT OR UPDATE ON public.emergency_requests
    FOR EACH ROW
    EXECUTE FUNCTION public.notify_emergency_events();

-- ============================================================================
-- 4. VISITS RLS â€” Add org_admin and admin visibility
-- ============================================================================
-- org_admin should see visits for users in their organization's hospitals
-- admin should see all visits

-- Admin can view all visits
DROP POLICY IF EXISTS "Admins can view all visits" ON public.visits;
CREATE POLICY "Admins can view all visits"
ON public.visits
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE profiles.id = auth.uid()
        AND profiles.role = 'admin'
    )
);

-- Org admin can view visits linked to their hospital
-- NOTE: profiles.organization_id points to hospitals.id (both TEXT after flexible_ids migration)
-- The sync_emergency_to_visit trigger already populates visits.hospital_id,
-- so we can match directly without joining emergency_requests.
DROP POLICY IF EXISTS "Org admins can view org visits" ON public.visits;
CREATE POLICY "Org admins can view org visits"
ON public.visits
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND visits.hospital_id IS NOT NULL
        AND visits.hospital_id = p.organization_id
    )
);

-- Admin can update all visits (for status management)
DROP POLICY IF EXISTS "Admins can update all visits" ON public.visits;
CREATE POLICY "Admins can update all visits"
ON public.visits
FOR UPDATE
USING (
    EXISTS (
        SELECT 1 FROM public.profiles
        WHERE profiles.id = auth.uid()
        AND profiles.role IN ('admin', 'org_admin')
    )
);

-- ============================================================================
-- 5. GRANTS & SCHEMA RELOAD
-- ============================================================================
GRANT EXECUTE ON FUNCTION public.release_ambulance_on_completion() TO authenticated;
GRANT EXECUTE ON FUNCTION public.sync_emergency_to_visit() TO authenticated;
GRANT EXECUTE ON FUNCTION public.notify_emergency_events() TO authenticated;

NOTIFY pgrst, 'reload schema';

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217190000_org_admin_multi_hospital_visits.sql
-- ----------------------------------------------------------------------------

-- ==========================================================================
-- ORG ADMIN MULTI-HOSPITAL VISITS RLS â€” 2026-02-17
-- ==========================================================================
-- Fix: An org_admin's profiles.organization_id points to a single hospital,
-- but they may manage multiple hospitals under one parent organization.
-- The RLS policy must resolve the parent org and match all sibling hospitals.
-- ==========================================================================
BEGIN;

-- Replace the single-hospital policy with a multi-hospital one
DROP POLICY IF EXISTS "Org admins can view org visits" ON public.visits;
CREATE POLICY "Org admins can view org visits"
ON public.visits
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals admin_h ON admin_h.id = p.organization_id
        JOIN public.hospitals visit_h ON visit_h.organization_id = admin_h.organization_id
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND visits.hospital_id IS NOT NULL
        AND visits.hospital_id = visit_h.id
    )
);

NOTIFY pgrst, 'reload schema';

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217200000_fix_org_admin_visits_rls.sql
-- ----------------------------------------------------------------------------

-- ==========================================================================
-- FIX ORG ADMIN VISITS RLS â€” profiles.organization_id = organizations.id
-- ==========================================================================
-- Corrects the wrong assumption that profiles.organization_id pointed to
-- hospitals.id. It actually stores the PARENT organization UUID (as TEXT).
-- hospitals.organization_id is UUID. We cast both to TEXT for safe comparison.
-- ==========================================================================
BEGIN;

DROP POLICY IF EXISTS "Org admins can view org visits" ON public.visits;
CREATE POLICY "Org admins can view org visits"
ON public.visits
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h 
            ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND visits.hospital_id IS NOT NULL
        AND visits.hospital_id = h.id
    )
);

NOTIFY pgrst, 'reload schema';

COMMIT;


-- ----------------------------------------------------------------------------
-- Source: 20260217210000_universal_org_admin_rbac.sql
-- ----------------------------------------------------------------------------

-- ==========================================================================
-- UNIVERSAL ORG ADMIN RBAC â€” 2026-02-17
-- ==========================================================================
-- Corrects Org Admin visibility across all core tables.
-- logic: profiles.organization_id = parent organization UUID (TEXT).
-- We resolve all hospitals belonging to that parent org and grant access.
-- ==========================================================================

BEGIN;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 1. DOCTORS
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Org admins can manage doctors in their hospitals
DROP POLICY IF EXISTS "Org admins manage their doctors" ON public.doctors;
CREATE POLICY "Org admins manage their doctors"
ON public.doctors
FOR ALL
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND doctors.hospital_id IS NOT NULL
        AND doctors.hospital_id = h.id
    )
)
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND doctors.hospital_id IS NOT NULL
        AND doctors.hospital_id = h.id
    )
);


-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 2. AMBULANCES
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Org admins can manage ambulances in their hospitals
DROP POLICY IF EXISTS "Org admins manage their ambulances" ON public.ambulances;
CREATE POLICY "Org admins manage their ambulances"
ON public.ambulances
FOR ALL
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND ambulances.hospital_id IS NOT NULL
        AND ambulances.hospital_id = h.id
    )
)
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND ambulances.hospital_id IS NOT NULL
        AND ambulances.hospital_id = h.id
    )
);


-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 3. EMERGENCY REQUESTS
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Modernize the emergency requests policy to use the same cast-safe join
DROP POLICY IF EXISTS "Org admins see their emergencies" ON public.emergency_requests;
CREATE POLICY "Org admins see their emergencies"
ON public.emergency_requests
FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND emergency_requests.hospital_id IS NOT NULL
        AND emergency_requests.hospital_id = h.id
    )
);

DROP POLICY IF EXISTS "Org admins update their emergencies" ON public.emergency_requests;
CREATE POLICY "Org admins update their emergencies"
ON public.emergency_requests
FOR UPDATE
USING (
    EXISTS (
        SELECT 1 FROM public.profiles p
        JOIN public.hospitals h ON CAST(h.organization_id AS text) = CAST(p.organization_id AS text)
        WHERE p.id = auth.uid()
        AND p.role = 'org_admin'
        AND p.organization_id IS NOT NULL
        AND emergency_requests.hospital_id IS NOT NULL
        AND emergency_requests.hospital_id = h.id
    )
);

COMMIT;

NOTIFY pgrst, 'reload schema';


