-- ============================================================================
-- SYSTEM FEATURE RESTORATION (RLS + TRIGGERS + AUTOMATIONS)
-- ============================================================================
-- 1. Restores the full set of Master RLS policies (casted for TEXT IDs).
-- 2. Restores User Onboarding Automations (Auth -> Profile -> Wallet).
-- 3. Restores Financial Ledgering (Payments -> Ledger).
-- 4. Restores ID Beautification (ORG-XXX, IVP-XXX prefixes).
-- ============================================================================

BEGIN;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 1. RE-APPLY MASTER RLS (CASTED FOR TEXT)
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- [Profiles]
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Users can view own profile" ON public.profiles;
CREATE POLICY "Users can view own profile" ON public.profiles FOR SELECT USING (id::text = auth.uid()::text);
DROP POLICY IF EXISTS "Users can update own profile" ON public.profiles;
CREATE POLICY "Users can update own profile" ON public.profiles FOR UPDATE USING (id::text = auth.uid()::text);

-- [Hospitals]
ALTER TABLE public.hospitals ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Authenticated users can view hospitals" ON public.hospitals;
CREATE POLICY "Authenticated users can view hospitals" ON public.hospitals FOR SELECT USING (auth.role() = 'authenticated');
DROP POLICY IF EXISTS "Platform Admins can manage hospitals" ON public.hospitals;
CREATE POLICY "Platform Admins can manage hospitals" ON public.hospitals FOR ALL USING (public.get_current_user_role() = 'admin');

-- [Emergency Requests]
ALTER TABLE public.emergency_requests ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Users manage own emergencies" ON public.emergency_requests;
CREATE POLICY "Users manage own emergencies" ON public.emergency_requests FOR ALL USING (user_id::text = auth.uid()::text);
DROP POLICY IF EXISTS "Admins view all emergencies" ON public.emergency_requests;
CREATE POLICY "Admins view all emergencies" ON public.emergency_requests FOR ALL USING (public.get_current_user_role() IN ('admin', 'org_admin', 'dispatcher'));

-- [Visits]
ALTER TABLE public.visits ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Users can view own visits" ON public.visits;
CREATE POLICY "Users can view own visits" ON public.visits FOR SELECT USING (user_id::text = auth.uid()::text);

-- [Wallets]
ALTER TABLE public.patient_wallets ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Users manage own patient wallet" ON public.patient_wallets;
CREATE POLICY "Users manage own patient wallet" ON public.patient_wallets FOR ALL USING (user_id::text = auth.uid()::text);

ALTER TABLE public.organization_wallets ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Org admins view their own wallet" ON public.organization_wallets;
CREATE POLICY "Org admins view their own wallet" ON public.organization_wallets FOR SELECT USING (
    organization_id::text = (SELECT organization_id FROM public.profiles WHERE id = auth.uid()) OR public.get_current_user_role() = 'admin'
);

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 2. RESTORE ONBOARDING ENGINE
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Handle New User (Auth -> Profile)
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.profiles (id, email, phone, full_name, avatar_url, updated_at)
  VALUES (NEW.id, NEW.email, NEW.phone, NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'avatar_url', now())
  ON CONFLICT (id) DO UPDATE SET email = EXCLUDED.email, phone = EXCLUDED.phone, updated_at = now();
  
  INSERT INTO public.preferences (user_id) VALUES (NEW.id) ON CONFLICT (user_id) DO NOTHING;
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- Handle Profile Features (Wallet & Medical)
CREATE OR REPLACE FUNCTION public.handle_new_profile_features()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.medical_profiles (user_id) VALUES (NEW.id) ON CONFLICT (user_id) DO NOTHING;
  INSERT INTO public.patient_wallets (user_id) VALUES (NEW.id) ON CONFLICT (user_id) DO NOTHING;
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS tr_on_profile_created_features ON public.profiles;
CREATE TRIGGER tr_on_profile_created_features AFTER INSERT ON public.profiles FOR EACH ROW EXECUTE FUNCTION public.handle_new_profile_features();

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 3. RESTORE FINANCIAL ENGINE (Ledger)
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
CREATE OR REPLACE FUNCTION public.process_payment_with_ledger()
RETURNS TRIGGER AS $$
DECLARE
    v_organization_id TEXT;
    v_fee_amount DECIMAL;
    v_organization_amount DECIMAL;
    v_fee_rate DECIMAL;
    v_main_wallet_id UUID;
    v_org_wallet_id UUID;
    v_already_credited BOOLEAN;
BEGIN
    v_already_credited := COALESCE((NEW.metadata->>'ledger_credited')::boolean, false);

    IF NEW.organization_id IS NULL AND NEW.emergency_request_id IS NOT NULL THEN
        SELECT h.organization_id::text INTO v_organization_id
        FROM public.emergency_requests er
        JOIN public.hospitals h ON er.hospital_id = h.id
        WHERE er.id = NEW.emergency_request_id;
        NEW.organization_id := v_organization_id;
    END IF;

    IF NEW.status = 'completed' AND NOT v_already_credited AND NEW.organization_id IS NOT NULL THEN
        SELECT ivisit_fee_percentage INTO v_fee_rate FROM public.organizations WHERE id = NEW.organization_id;
        v_fee_rate := COALESCE(v_fee_rate, 2.5);
        v_fee_amount := (NEW.amount * v_fee_rate) / 100;
        v_organization_amount := NEW.amount - v_fee_amount;
        
        NEW.metadata := jsonb_set(COALESCE(NEW.metadata, '{}'::jsonb), '{ledger_credited}', 'true');
        
        -- Platform Fee
        SELECT id INTO v_main_wallet_id FROM public.ivisit_main_wallet LIMIT 1;
        UPDATE public.ivisit_main_wallet SET balance = balance + v_fee_amount WHERE id = v_main_wallet_id;
        INSERT INTO public.wallet_ledger (wallet_type, wallet_id, amount, transaction_type, reference_id, reference_type)
        VALUES ('main', v_main_wallet_id::text, v_fee_amount, 'credit', NEW.id, 'payment');

        -- Org Balance
        INSERT INTO public.organization_wallets (organization_id, balance) 
        VALUES (NEW.organization_id, v_organization_amount)
        ON CONFLICT (organization_id) DO UPDATE SET balance = organization_wallets.balance + v_organization_amount RETURNING id INTO v_org_wallet_id;
        
        INSERT INTO public.wallet_ledger (wallet_type, wallet_id, organization_id, amount, transaction_type, reference_id, reference_type)
        VALUES ('organization', v_org_wallet_id::text, NEW.organization_id, v_organization_amount, 'credit', NEW.id, 'payment');
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS tr_process_payment_with_ledger ON public.payments;
CREATE TRIGGER tr_process_payment_with_ledger BEFORE UPDATE ON public.payments
FOR EACH ROW WHEN (OLD.status IS DISTINCT FROM NEW.status) EXECUTE FUNCTION public.process_payment_with_ledger();

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 4. RESTORE ID BEAUTIFICATION
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
CREATE OR REPLACE FUNCTION public.generate_display_id(prefix TEXT)
RETURNS TEXT AS $$
DECLARE
    new_id TEXT;
    random_num TEXT;
BEGIN
    random_num := LPAD(FLOOR(RANDOM() * 1000000)::TEXT, 6, '0');
    new_id := prefix || '-' || random_num;
    RETURN new_id;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION public.stamp_entity_display_id()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE prefix TEXT;
BEGIN
  IF TG_TABLE_NAME = 'hospitals' THEN prefix := 'ORG';
  ELSIF TG_TABLE_NAME = 'profiles' THEN prefix := 'USR';
  ELSIF TG_TABLE_NAME = 'emergency_requests' THEN prefix := 'AMB';
  ELSE prefix := 'GEN';
  END IF;
  
  IF NEW.display_id IS NULL THEN
    NEW.display_id := public.generate_display_id(prefix);
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS tr_stamp_hospital_id ON public.hospitals;
CREATE TRIGGER tr_stamp_hospital_id BEFORE INSERT ON public.hospitals FOR EACH ROW EXECUTE FUNCTION public.stamp_entity_display_id();

DROP TRIGGER IF EXISTS tr_stamp_profile_id ON public.profiles;
CREATE TRIGGER tr_stamp_profile_id BEFORE INSERT ON public.profiles FOR EACH ROW EXECUTE FUNCTION public.stamp_entity_display_id();

DROP TRIGGER IF EXISTS tr_stamp_request_id ON public.emergency_requests;
CREATE TRIGGER tr_stamp_request_id BEFORE INSERT ON public.emergency_requests FOR EACH ROW EXECUTE FUNCTION public.stamp_entity_display_id();

COMMIT;
NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260218002000_console_rpc_restoration.sql
-- ----------------------------------------------------------------------------

-- Migration: Master Console & Admin RPC Restoration
-- Author: Antigravity
-- Date: 2026-02-18
-- Description: Restores critical RPC functions required by the iVisit Console and Admin dashboard.
-- Targets: User management, statistics, and administrative controls.

BEGIN;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 1. UTILITY FUNCTIONS
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Check if current user is admin
CREATE OR REPLACE FUNCTION public.is_admin()
RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public AS $$
  SELECT EXISTS (SELECT 1 FROM public.profiles WHERE id::text = auth.uid()::text AND role = 'admin');
$$;

-- Alias for frontend compatibility
CREATE OR REPLACE FUNCTION public.current_user_is_admin()
RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public AS $$
  SELECT public.is_admin();
$$;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 2. USER MANAGEMENT RPCs
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Get all auth users with profile data (Admin only)
-- Scoped by organization_id (TEXT-compatible)
DROP FUNCTION IF EXISTS public.get_all_auth_users(uuid);
DROP FUNCTION IF EXISTS public.get_all_auth_users(text);

CREATE OR REPLACE FUNCTION public.get_all_auth_users(p_organization_id text DEFAULT NULL)
RETURNS TABLE (
    id uuid, email text, phone text, username text, role text, full_name text, 
    avatar_url text, organization_id text, provider_type text, bvn_verified boolean, 
    display_id text, created_at timestamptz, last_sign_in_at timestamptz,
    organization_name text
) LANGUAGE plpgsql SECURITY DEFINER AS $$
BEGIN
    RETURN QUERY
    SELECT 
        au.id, 
        au.email::text, 
        au.phone::text, 
        p.username, 
        p.role, 
        p.full_name, 
        p.image_uri as avatar_url, 
        p.organization_id,
        p.provider_type, 
        p.bvn_verified, 
        p.display_id, 
        au.created_at, 
        au.last_sign_in_at,
        o.name as organization_name
    FROM auth.users au
    LEFT JOIN public.profiles p ON au.id = p.id
    LEFT JOIN public.organizations o ON p.organization_id = o.id
    WHERE (p_organization_id IS NULL OR 
           p_organization_id = '' OR 
           p.organization_id = p_organization_id)
    ORDER BY au.created_at DESC;
END;
$$;

-- Search auth users (Admin only)
DROP FUNCTION IF EXISTS public.search_auth_users(text);

CREATE OR REPLACE FUNCTION public.search_auth_users(search_term text)
RETURNS TABLE (
    id uuid, email text, phone text, created_at timestamptz, last_sign_in_at timestamptz,
    email_confirmed_at timestamptz, profile_role text, profile_username text, 
    profile_first_name text, profile_last_name text, profile_full_name text, 
    profile_provider_type text
) LANGUAGE sql SECURITY DEFINER SET search_path = public AS $$
  SELECT 
    au.id, au.email::text, au.phone::text, au.created_at, au.last_sign_in_at, au.email_confirmed_at,
    p.role as profile_role, p.username as profile_username, p.first_name as profile_first_name,
    p.last_name as profile_last_name, p.full_name as profile_full_name, p.provider_type as profile_provider_type
  FROM auth.users au
  LEFT JOIN public.profiles p ON au.id = p.id
  WHERE (
    LOWER(au.email) LIKE LOWER('%' || search_term || '%') OR
    LOWER(p.username) LIKE LOWER('%' || search_term || '%') OR
    LOWER(p.full_name) LIKE LOWER('%' || search_term || '%')
  );
$$;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 3. STATISTICS & ANALYTICS
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Get user statistics (Admin only)
DROP FUNCTION IF EXISTS public.get_user_statistics(uuid);
DROP FUNCTION IF EXISTS public.get_user_statistics(text);

CREATE OR REPLACE FUNCTION public.get_user_statistics(p_organization_id text DEFAULT NULL)
RETURNS TABLE (
  total_users bigint,
  total_profiles bigint,
  recent_signups bigint,
  email_verified_users bigint,
  phone_verified_users bigint,
  admin_count bigint,
  provider_count bigint,
  sponsor_count bigint,
  viewer_count bigint,
  patient_count bigint,
  org_admin_count bigint,
  dispatcher_count bigint
) LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
    RETURN QUERY
    WITH 
    user_stats AS (
        SELECT 
            COUNT(*) as total_users,
            COUNT(CASE WHEN au.email_confirmed_at IS NOT NULL THEN 1 END) as email_verified_users,
            COUNT(CASE WHEN au.phone_confirmed_at IS NOT NULL THEN 1 END) as phone_verified_users,
            COUNT(CASE WHEN p.created_at >= NOW() - INTERVAL '30 days' THEN 1 END) as recent_signups
        FROM public.profiles p
        LEFT JOIN auth.users au ON au.id = p.id
        WHERE (p_organization_id IS NULL OR p_organization_id = '' OR p.organization_id = p_organization_id)
    ),
    profile_stats AS (
        SELECT 
            COUNT(*) as total_profiles,
            COUNT(CASE WHEN p3.role = 'admin' THEN 1 END) as admin_count,
            COUNT(CASE WHEN p3.role = 'provider' THEN 1 END) as provider_count,
            COUNT(CASE WHEN p3.role = 'sponsor' THEN 1 END) as sponsor_count,
            COUNT(CASE WHEN p3.role = 'viewer' THEN 1 END) as viewer_count,
            COUNT(CASE WHEN p3.role = 'patient' THEN 1 END) as patient_count,
            COUNT(CASE WHEN p3.role = 'org_admin' THEN 1 END) as org_admin_count,
            COUNT(CASE WHEN p3.role = 'dispatcher' THEN 1 END) as dispatcher_count
        FROM public.profiles p3
        WHERE (p_organization_id IS NULL OR p_organization_id = '' OR p_organization_id = p3.organization_id)
    )
    SELECT 
        us.total_users, ps.total_profiles, us.recent_signups, us.email_verified_users, 
        us.phone_verified_users, ps.admin_count, ps.provider_count, ps.sponsor_count, 
        ps.viewer_count, ps.patient_count, ps.org_admin_count, ps.dispatcher_count
    FROM user_stats us, profile_stats ps;
END;
$$;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 4. ADMINISTRATIVE CONTROLS
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

-- Delete user (Admin only)
CREATE OR REPLACE FUNCTION public.delete_user_by_admin(target_user_id text)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
BEGIN
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Access Denied: Only platform admins can delete users.';
    END IF;
    DELETE FROM auth.users WHERE id::text = target_user_id;
END;
$$;

-- Update profile (Admin/Org Admin only)
CREATE OR REPLACE FUNCTION public.update_profile_by_admin(target_user_id text, profile_data jsonb)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
  result jsonb;
BEGIN
    IF NOT (public.get_current_user_role() IN ('admin', 'org_admin')) THEN
        RAISE EXCEPTION 'Access Denied: Insufficient permissions to update other users.';
    END IF;

    UPDATE public.profiles
    SET 
        username = COALESCE(profile_data->>'username', username),
        role = COALESCE(profile_data->>'role', role),
        organization_id = CASE WHEN profile_data ? 'organization_id' THEN (profile_data->>'organization_id')::text ELSE organization_id END,
        full_name = COALESCE(profile_data->>'full_name', full_name),
        provider_type = COALESCE(profile_data->>'provider_type', provider_type),
        bvn_verified = COALESCE((profile_data->>'bvn_verified')::boolean, bvn_verified),
        updated_at = now()
    WHERE id::text = target_user_id
    RETURNING to_jsonb(profiles) INTO result;

    RETURN result;
END;
$$;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 5. GRANTS & CLEANUP
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

GRANT EXECUTE ON FUNCTION public.get_all_auth_users(text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.search_auth_users(text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_user_statistics(text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.delete_user_by_admin(text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.update_profile_by_admin(text, jsonb) TO authenticated;
GRANT EXECUTE ON FUNCTION public.current_user_is_admin() TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_admin() TO authenticated;

COMMIT;

-- Reload PGRST cache
NOTIFY pgrst, 'reload schema';


-- ----------------------------------------------------------------------------
-- Source: 20260218002500_rpc_type_alignment.sql
-- ----------------------------------------------------------------------------

-- Migration: RPC Type Alignment for TEXT IDs
-- Author: Antigravity
-- Date: 2026-02-18
-- Description: Fixes remaining RPCs that incorrectly cast TEXT organization IDs to UUID.

BEGIN;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 1. FIX: process_cash_payment_v2
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
CREATE OR REPLACE FUNCTION public.process_cash_payment_v2(
    p_emergency_request_id TEXT,
    p_organization_id TEXT,
    p_amount NUMERIC,
    p_currency TEXT DEFAULT 'USD'
) RETURNS JSONB AS $$
DECLARE
    v_payment_id UUID;
    v_user_id UUID;
    v_fee_rate NUMERIC;
    v_fee_amount NUMERIC;
    v_wallet_id UUID;
    v_main_wallet_id UUID;
BEGIN
    -- We use p_organization_id directly as TEXT
    
    SELECT user_id INTO v_user_id FROM public.emergency_requests 
    WHERE id::text = p_emergency_request_id;

    -- 1. Calculate Fee
    SELECT ivisit_fee_percentage INTO v_fee_rate FROM public.organizations WHERE id = p_organization_id;
    v_fee_rate := COALESCE(v_fee_rate, 2.5);
    v_fee_amount := (p_amount * v_fee_rate) / 100;

    -- 2. Debit Org Wallet
    UPDATE public.organization_wallets 
    SET balance = balance - v_fee_amount, updated_at = NOW()
    WHERE organization_id = p_organization_id
    RETURNING id INTO v_wallet_id;

    IF v_wallet_id IS NOT NULL THEN
        INSERT INTO public.wallet_ledger (
            wallet_type, wallet_id, organization_id, amount, 
            transaction_type, description, reference_id, reference_type
        ) VALUES (
            'organization', v_wallet_id, p_organization_id, -v_fee_amount,
            'debit', 'Protocol Fee (Cash Job)', p_emergency_request_id::UUID, 'emergency_request'
        );
    END IF;

    -- 3. Credit Platform Wallet
    SELECT id INTO v_main_wallet_id FROM public.ivisit_main_wallet LIMIT 1;
    UPDATE public.ivisit_main_wallet 
    SET balance = balance + v_fee_amount, updated_at = NOW() 
    WHERE id = v_main_wallet_id;

    INSERT INTO public.wallet_ledger (
        wallet_type, wallet_id, organization_id, amount, 
        transaction_type, description, reference_id, reference_type
    ) VALUES (
        'main', v_main_wallet_id, NULL, v_fee_amount,
        'credit', 'Fee from Cash Job ' || p_emergency_request_id, p_emergency_request_id::UUID, 'emergency_request'
    );

    -- 4. Record Payment
    INSERT INTO public.payments (
        user_id, amount, currency, status, payment_method_id, 
        emergency_request_id, organization_id, metadata
    ) VALUES (
        v_user_id, p_amount, p_currency, 'completed', 'cash', 
        p_emergency_request_id::UUID, p_organization_id,
        jsonb_build_object('source', 'cash_payment', 'protocol_fee', v_fee_amount, 'ledger_credited', true)
    ) RETURNING id INTO v_payment_id;

    -- 5. Complete Request
    UPDATE public.emergency_requests SET payment_status = 'completed'
    WHERE id::text = p_emergency_request_id;

    RETURN jsonb_build_object('success', true, 'payment_id', v_payment_id, 'fee_deducted', v_fee_amount);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 2. FIX: process_wallet_payment
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
CREATE OR REPLACE FUNCTION public.process_wallet_payment(
    p_user_id TEXT,
    p_organization_id TEXT,
    p_emergency_request_id TEXT,
    p_amount DECIMAL,
    p_currency TEXT
)
RETURNS JSONB AS $$
DECLARE
    v_user_uuid UUID;
    v_req_uuid UUID;
    v_patient_wallet_id UUID;
    v_patient_balance DECIMAL;
    v_payment_id UUID;
BEGIN
    BEGIN
        v_user_uuid := p_user_id::UUID;
        v_req_uuid := p_emergency_request_id::UUID;
        -- p_organization_id is TEXT, no cast needed to UUID
    EXCEPTION WHEN OTHERS THEN
        RETURN jsonb_build_object('success', false, 'error', 'Invalid UUID format provided for user or request');
    END;

    SELECT id, balance INTO v_patient_wallet_id, v_patient_balance
    FROM public.patient_wallets
    WHERE user_id = v_user_uuid;
    
    IF v_patient_wallet_id IS NULL THEN
        INSERT INTO public.patient_wallets (user_id, balance, currency)
        VALUES (v_user_uuid, 0.00, p_currency)
        RETURNING id, balance INTO v_patient_wallet_id, v_patient_balance;
    END IF;

    IF v_patient_balance < p_amount THEN
        RETURN jsonb_build_object('success', false, 'error', 'Insufficient wallet balance. Please top up.');
    END IF;

    UPDATE public.patient_wallets
    SET balance = balance - p_amount, updated_at = NOW()
    WHERE id = v_patient_wallet_id;

    INSERT INTO public.wallet_ledger (
        wallet_type, wallet_id, user_id, amount, 
        transaction_type, description, reference_id, reference_type
    ) VALUES (
        'patient', v_patient_wallet_id, v_user_uuid, -p_amount,
        'debit', 'Service Payment (Wallet)', v_req_uuid, 'emergency_request'
    );

    INSERT INTO public.payments (
        user_id, amount, currency, status, 
        payment_method_id, emergency_request_id, organization_id, metadata
    ) VALUES (
        v_user_uuid, p_amount, p_currency, 'completed',
        'wallet_' || v_patient_wallet_id::text,
        v_req_uuid, p_organization_id,
        jsonb_build_object('source', 'patient_wallet', 'wallet_id', v_patient_wallet_id)
    )
    RETURNING id INTO v_payment_id;

    RETURN jsonb_build_object(
        'success', true,
        'payment_id', v_payment_id,
        'new_balance', (SELECT balance FROM public.patient_wallets WHERE id = v_patient_wallet_id)
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
-- 3. FIX: calculate_emergency_cost (ensure v_org_id is TEXT)
-- â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
CREATE OR REPLACE FUNCTION public.calculate_emergency_cost(
    p_service_type TEXT,
    p_hospital_id TEXT DEFAULT NULL,
    p_ambulance_id TEXT DEFAULT NULL,
    p_room_id TEXT DEFAULT NULL,
    p_distance NUMERIC DEFAULT 0,
    p_is_urgent BOOLEAN DEFAULT false
)
RETURNS TABLE (
    base_cost NUMERIC,
    distance_surcharge NUMERIC,
    urgency_surcharge NUMERIC,
    platform_fee NUMERIC,
    total_cost NUMERIC,
    breakdown JSONB
) LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
    v_base_cost NUMERIC := 0;
    v_distance_surcharge NUMERIC := 0;
    v_urgency_surcharge NUMERIC := 0;
    v_platform_fee NUMERIC := 0;
    v_total_cost NUMERIC := 0;
    v_breakdown JSONB := '[]'::jsonb;
    v_service_name TEXT;
    v_org_id TEXT;
    v_platform_fee_rate NUMERIC := 2.5; 
BEGIN
    -- Get Org ID from Hospital context (TEXT)
    SELECT h.organization_id INTO v_org_id FROM public.hospitals h WHERE h.id::text = p_hospital_id;

    -- Determine Base Cost
    IF p_ambulance_id IS NOT NULL AND p_ambulance_id != '' THEN
        SELECT a.base_price, 'Ambulance (' || a.license_plate || ')' INTO v_base_cost, v_service_name
        FROM public.ambulances a WHERE a.id::text = p_ambulance_id;
    END IF;

    IF (v_base_cost IS NULL OR v_base_cost = 0) AND p_service_type IN ('bed', 'bed_booking') AND p_room_id IS NOT NULL AND p_room_id != '' THEN
        SELECT hr.base_price, hr.room_type INTO v_base_cost, v_service_name
        FROM public.hospital_rooms hr WHERE hr.id::text = p_room_id;
    END IF;

    IF v_base_cost IS NULL OR v_base_cost = 0 THEN
        SELECT sp.base_price, sp.service_name INTO v_base_cost, v_service_name
        FROM public.service_pricing sp
        WHERE sp.service_type = p_service_type AND sp.is_active = true
          AND (sp.hospital_id::text = p_hospital_id OR sp.organization_id = v_org_id OR (sp.hospital_id IS NULL AND sp.organization_id IS NULL))
        ORDER BY (sp.hospital_id::text = p_hospital_id) DESC, (sp.organization_id = v_org_id) DESC LIMIT 1;
    END IF;

    -- Fallbacks
    IF v_base_cost IS NULL OR v_base_cost = 0 THEN
        v_base_cost := CASE WHEN p_service_type = 'ambulance' THEN 150.00 ELSE 200.00 END;
        v_service_name := CASE WHEN p_service_type = 'ambulance' THEN 'Ambulance Service' ELSE 'Medical Resource' END;
    END IF;

    v_distance_surcharge := CASE WHEN p_distance > 5 THEN (p_distance - 5) * 2.00 ELSE 0 END;
    v_urgency_surcharge := CASE WHEN p_is_urgent THEN 25.00 ELSE 0 END;
    v_total_cost := v_base_cost + v_distance_surcharge + v_urgency_surcharge;

    -- Platform Fee
    IF v_org_id IS NOT NULL THEN
        SELECT ivisit_fee_percentage INTO v_platform_fee_rate FROM public.organizations WHERE id = v_org_id;
    END IF;
    v_platform_fee_rate := COALESCE(v_platform_fee_rate, 2.5);
    v_total_cost := v_total_cost / (1 - (v_platform_fee_rate / 100));
    v_platform_fee := v_total_cost - (v_base_cost + v_distance_surcharge + v_urgency_surcharge);

    v_breakdown := jsonb_build_array(
        jsonb_build_object('name', v_service_name, 'cost', ROUND(v_base_cost::numeric, 2), 'type', 'base'),
        jsonb_build_object('name', 'Distance Surcharge', 'cost', ROUND(v_distance_surcharge::numeric, 2), 'type', 'distance'),
        jsonb_build_object('name', 'Urgency Surcharge', 'cost', ROUND(v_urgency_surcharge::numeric, 2), 'type', 'urgency'),
        jsonb_build_object('name', 'iVisit Fee (' || v_platform_fee_rate || '%)', 'cost', ROUND(v_platform_fee::numeric, 2), 'type', 'fee')
    );

    RETURN QUERY SELECT 
        ROUND(v_base_cost::numeric, 2), ROUND(v_distance_surcharge::numeric, 2), ROUND(v_urgency_surcharge::numeric, 2),
        ROUND(v_platform_fee::numeric, 2), ROUND(v_total_cost::numeric, 2), v_breakdown;
END;
$$;

