RETURNS JSONB LANGUAGE sql SECURITY DEFINER AS $$
  SELECT jsonb_agg(t) FROM (
    SELECT id, 'Emergency Request' as type, status, created_at 
    FROM public.emergency_requests 
    ORDER BY created_at DESC LIMIT p_limit
  ) t;
$$;

